var __index = {"config":{"lang":["zh","en"],"separator":"[\\s\\u200b\\u3000\\-\u3001\u3002\uff0c\uff0e\uff1f\uff01\uff1b]+","pipeline":["stemmer"],"fields":{"title":{"boost":1000.0},"text":{"boost":1.0},"tags":{"boost":1000000.0}}},"docs":[{"location":"index.html","title":"MSTLMinecraft Terminal Server Launcher","text":"\ud83d\udc19 v1.1.0 \u00b7 GPLv3 \u00b7 \u96f6\u5916\u90e8\u4f9d\u8d56 <p>\u8f7b\u91cf\u7ea7 \u00b7 \u96f6\u5916\u90e8\u4f9d\u8d56 \u00b7 \u8de8\u5e73\u53f0Minecraft \u670d\u52a1\u7aef\u7ba1\u7406\u5668</p> MSTL \u2014 Server Console $ python start.py # \u9996\u6b21\u8fd0\u884c\u81ea\u52a8\u521b\u5efa config.json \u548c servers/ \u9009\u62e9\u8981\u542f\u52a8\u7684\u670d\u52a1\u5668:   [1] \u751f\u5b58\u670d-1.21  MC 1.21.1 | paper.jar | 2G/8G   [2] \u521b\u9020\u670d-1.20  MC 1.20.4 | vanilla.jar | 4G/16G   [0] \u9000\u51fa &gt; 1 Java \u68c0\u6d4b\u5230 Adoptium JDK 21.0.2 \u7248\u672c MC 1.21.1 \u2192 Java 21 \u2713 \u517c\u5bb9 \u542f\u52a8 \u5185\u5b58 min 2G / max 8G \u5c31\u7eea \u670d\u52a1\u5668\u6b63\u5728\u542f\u52a8\uff0c\u76d1\u542c *:25565 \u5b8c\u6210 Done (2.1s)! \u8f93\u5165 \"help\" \u83b7\u53d6\u5e2e\u52a9 &gt;"},{"location":"index.html#_1","title":"\ud83d\udcca \u6570\u636e\u4e00\u89c8","text":"30+\u670d\u52a1\u7aef\u7c7b\u578b 3\u63d2\u4ef6\u5e02\u573a 2\u6a21\u7ec4\u6e90 0\u5916\u90e8\u4f9d\u8d56 3\u8bed\u8a00\u652f\u6301"},{"location":"index.html#_2","title":"\ud83d\udda5 \u6838\u5fc3\u529f\u80fd","text":"\ud83d\udccb \u591a\u5b9e\u4f8b\u7ba1\u7406 <p>\u6bcf\u4e2a\u670d\u52a1\u5668\u72ec\u7acb\u76ee\u5f55\uff0c\u4e92\u4e0d\u5e72\u6270\u3002\u652f\u6301 Paper\u3001Purpur\u3001Fabric\u3001Forge\u3001NeoForge\u3001Velocity \u7b49 30+ \u79cd\u670d\u52a1\u7aef\u6838\u5fc3\u3002</p> \u2615 \u81ea\u52a8 Java \u7ba1\u7406 <p>\u626b\u63cf\u7cfb\u7edf\u73af\u5883\u53d8\u91cf\u4e0e\u5b89\u88c5\u8def\u5f84\uff0c\u81ea\u52a8\u68c0\u6d4b Java \u7248\u672c\uff1b\u4e0d\u517c\u5bb9\u65f6\u4e00\u952e\u4e0b\u8f7d GraalVM JDK\uff0817 / 21 / 25\uff09\u3002</p> \u2b07\ufe0f \u591a\u7ebf\u7a0b\u4e0b\u8f7d <p>\u670d\u52a1\u7aef\u6838\u5fc3\u3001\u63d2\u4ef6\u3001\u6a21\u7ec4\u5747\u4f7f\u7528 16 \u7ebf\u7a0b\u5e76\u53d1\u5206\u5757\u4e0b\u8f7d\uff0c\u81ea\u52a8\u68c0\u6d4b Range \u652f\u6301\u5e76\u56de\u9000\u5230\u5355\u7ebf\u7a0b\u3002</p> \ud83e\udde9 \u63d2\u4ef6\u7ba1\u7406 <p>\u96c6\u6210 SpigotMC\uff08Spiget\uff09\u3001Modrinth\u3001Hangar \u4e09\u5927\u63d2\u4ef6\u6e90\uff0c\u5e76\u884c\u641c\u7d22\uff0c\u6309\u4e0b\u8f7d\u91cf\u6392\u5e8f\uff0c\u4e00\u952e\u4e0b\u8f7d\u5b89\u88c5\u3002</p> \ud83d\udce6 \u6a21\u7ec4\u7ba1\u7406 <p>Modrinth \u548c CurseForge \u53cc\u6e90\u641c\u7d22\uff0c\u81ea\u52a8\u6309 MC \u7248\u672c\u548c\u52a0\u8f7d\u5668\u8fc7\u6ee4\uff0c\u7ed3\u679c\u4e0d\u8db3\u65f6\u81ea\u52a8\u653e\u5bbd\u8303\u56f4\u3002</p> \ud83d\ude87 \u5185\u7f51\u7a7f\u900f <p>\u96c6\u6210 OpenFrp \u96a7\u9053\u7ba1\u7406\uff0c\u81ea\u52a8\u4e0b\u8f7d\u5339\u914d\u7cfb\u7edf\u67b6\u6784\u7684 frpc\uff0c\u7ed1\u5b9a\u540e\u968f\u670d\u52a1\u5668\u81ea\u52a8\u542f\u505c\u3002</p> \ud83d\udcbb \u4ea4\u4e92\u63a7\u5236\u53f0 <p>\u7ec8\u7aef\u5185\u76f4\u63a5\u5411\u670d\u52a1\u5668\u53d1\u9001\u6307\u4ee4\uff0c\u5b9e\u65f6\u67e5\u770b\u65e5\u5fd7\u8f93\u51fa\u3002\u652f\u6301 stop\u3001say\u3001whitelist\u3001op \u7b49\u4efb\u610f\u6307\u4ee4\u3002</p> \ud83c\udf10 \u56fd\u9645\u5316 <p>\u5185\u7f6e\u4e2d\u6587\u3001\u82f1\u6587\u3001\u4fc4\u8bed\u754c\u9762\uff0c\u5728 locales/ \u4e2d\u653e\u5165 JSON \u6587\u4ef6\u5373\u53ef\u6dfb\u52a0\u66f4\u591a\u8bed\u8a00\u3002</p>"},{"location":"index.html#_3","title":"\ud83d\ude80 \u5feb\u901f\u5f00\u59cb","text":"<pre><code>git clone https://github.com/yzsyzdy/mc-server-launcher.git\ncd mc-server-launcher\npython start.py\n</code></pre> <p>\u524d\u7f6e\u6761\u4ef6</p> <ul> <li>Python 3.10+\uff08\u4ec5\u6807\u51c6\u5e93\uff0c\u96f6\u7b2c\u4e09\u65b9\u4f9d\u8d56\uff09</li> <li>Java\uff08\u53ef\u9009 \u2014\u2014 \u65e0 Java \u65f6\u542f\u52a8\u5668\u53ef\u81ea\u52a8\u4e0b\u8f7d JDK 21\uff09</li> </ul>"},{"location":"index.html#_4","title":"\ud83d\uddfa \u9879\u76ee\u8def\u7ebf","text":"<ul> <li>\u2705 \u670d\u52a1\u7aef\u591a\u5b9e\u4f8b\u7ba1\u7406</li> <li>\u2705 \u81ea\u52a8 Java \u68c0\u6d4b\u4e0e\u4e0b\u8f7d</li> <li>\u2705 \u63d2\u4ef6\u641c\u7d22\u4e0e\u5b89\u88c5\uff08SpigotMC / Modrinth / Hangar\uff09</li> <li>\u2705 \u6a21\u7ec4\u641c\u7d22\u4e0e\u5b89\u88c5\uff08Modrinth / CurseForge\uff09</li> <li>\u2705 \u591a\u7ebf\u7a0b\u4e0b\u8f7d\u5f15\u64ce</li> <li>\u2705 OpenFrp \u5185\u7f51\u7a7f\u900f\u96c6\u6210</li> <li>\u2705 \u56fd\u9645\u5316\uff08\u4e2d\u6587 / English / \u0420\u0443\u0441\u0441\u043a\u0438\u0439\uff09</li> <li>\u2b55 \u56fe\u5f62\u5316\u754c\u9762</li> <li>\u2b55 \u8fdc\u7a0b Web \u63a7\u5236\u9762\u677f</li> </ul>"},{"location":"index.html#_5","title":"\u2696 \u8bb8\u53ef","text":"<p>GNU General Public License v3.0</p>"},{"location":"faq.html","title":"\u5e38\u89c1\u95ee\u9898","text":""},{"location":"faq.html#curseforge","title":"CurseForge \u641c\u7d22\u4e0d\u751f\u6548\uff1f","text":"<p>\u9700\u8981\u5728 <code>config.json</code> \u4e2d\u914d\u7f6e <code>curseforge_api_key</code>\u3002\u53ef\u524d\u5f80 CurseForge Console \u514d\u8d39\u7533\u8bf7 API key\u3002</p> <pre><code>{\n  \"curseforge_api_key\": \"\u4f60\u7684-api-key\"\n}\n</code></pre>"},{"location":"faq.html#spigotmc","title":"\u63d2\u4ef6\u4ece SpigotMC \u4e0b\u8f7d\u5931\u8d25\uff1f","text":"<p>\u90e8\u5206\u63d2\u4ef6\u4e0d\u76f4\u63a5\u6258\u7ba1\u5728 SpigotMC \u4e0a\uff0c\u800c\u662f\u6307\u5411\u5916\u90e8\u7ad9\u70b9\uff08\u5982 GitHub\uff09\u3002MSTL \u4f1a\u81ea\u52a8\u68c0\u6d4b\u8fd9\u79cd\u60c5\u51b5\u5e76\u5c1d\u8bd5\u901a\u8fc7 GitHub API \u83b7\u53d6\u5b9e\u9645\u7684 jar \u6587\u4ef6\u3002</p> <p>\u5982\u679c\u4ecd\u7136\u5931\u8d25\uff1a</p> <ol> <li>\u68c0\u67e5\u7f51\u7edc\u8fde\u63a5</li> <li>\u624b\u52a8\u590d\u5236\u63d0\u793a\u4e2d\u7684\u4e0b\u8f7d\u94fe\u63a5\uff0c\u5728\u6d4f\u89c8\u5668\u4e2d\u6253\u5f00</li> <li>\u4e0b\u8f7d\u540e\u901a\u8fc7\u300c\u5bfc\u5165\u672c\u5730 jar\u300d\u529f\u80fd\u5b89\u88c5</li> </ol>"},{"location":"faq.html#_2","title":"\u6a21\u7ec4\u641c\u7d22\u4e0d\u5230\u4e2d\u6587\u540d\u6a21\u7ec4\uff1f","text":"<p>Modrinth \u7684\u641c\u7d22\u7d22\u5f15\u4f9d\u8d56\u4e8e\u6a21\u7ec4\u7b80\u4ecb\u4e2d\u7684\u6587\u5b57\u5185\u5bb9\u3002\u7edd\u5927\u591a\u6570\u6a21\u7ec4\u4f7f\u7528\u82f1\u6587\u540d\u79f0\u548c\u82f1\u6587\u7b80\u4ecb\uff0c\u56e0\u6b64\u7528\u82f1\u6587\u5173\u952e\u8bcd\u641c\u7d22\u901a\u5e38\u6548\u679c\u66f4\u597d\u3002\u5982\u679c\u6a21\u7ec4\u7684\u7b80\u4ecb\u4e2d\u5305\u542b\u4e2d\u6587\u63cf\u8ff0\uff0c\u4e2d\u6587\u5173\u952e\u8bcd\u4e5f\u80fd\u641c\u5230\u3002</p>"},{"location":"faq.html#_3","title":"\u4e0b\u8f7d\u901f\u5ea6\u6162\uff1f","text":"<p>MSTL \u9ed8\u8ba4\u4f7f\u7528 16 \u7ebf\u7a0b\u5e76\u53d1\u4e0b\u8f7d\u3002\u53ef\u4ee5\u5728\u4ee3\u7801\u4e2d\u8c03\u7528 <code>set_download_threads(n)</code> \u8c03\u6574\u7ebf\u7a0b\u6570\u3002</p> <p>\u5982\u679c\u955c\u50cf\u7ad9\u4e0d\u652f\u6301 Range \u8bf7\u6c42\uff08\u5206\u5757\u4e0b\u8f7d\uff09\uff0c\u4f1a\u81ea\u52a8\u56de\u9000\u5230\u5355\u7ebf\u7a0b\u4e0b\u8f7d\u3002</p>"},{"location":"faq.html#java","title":"Java \u68c0\u6d4b\u4e0d\u5230\uff1f","text":"<p>MSTL \u4f1a\u6309\u4ee5\u4e0b\u987a\u5e8f\u67e5\u627e Java\uff1a</p> <ol> <li><code>config.json</code> \u4e2d <code>java_path</code> \u7684\u663e\u5f0f\u6307\u5b9a\u8def\u5f84</li> <li>\u7cfb\u7edf\u73af\u5883\u53d8\u91cf <code>JAVA_HOME</code></li> <li>\u7cfb\u7edf <code>PATH</code> \u4e2d\u7684 <code>java</code> \u547d\u4ee4</li> <li>\u6807\u51c6\u5b89\u88c5\u8def\u5f84\uff08\u5982 Windows \u7684 <code>Program Files\\Java\\</code>\uff09</li> </ol> <p>\u5982\u679c\u4ee5\u4e0a\u90fd\u627e\u4e0d\u5230\uff0c\u542f\u52a8\u670d\u52a1\u5668\u65f6 MSTL \u4f1a\u8be2\u95ee\u662f\u5426\u81ea\u52a8\u4e0b\u8f7d GraalVM JDK\u3002</p>"},{"location":"faq.html#_4","title":"\u5982\u4f55\u4fee\u6539\u670d\u52a1\u5668\u5185\u5b58\uff1f","text":"<p>\u7f16\u8f91\u670d\u52a1\u5668\u76ee\u5f55\u4e0b\u7684 <code>.server.json</code> \u6587\u4ef6\uff1a</p> <pre><code>{\n  \"min_mem\": \"2G\",\n  \"max_mem\": \"4G\"\n}\n</code></pre> <p><code>G</code> \u8868\u793a GB\uff0c<code>M</code> \u8868\u793a MB\u3002\u4fee\u6539\u540e\u91cd\u542f\u670d\u52a1\u5668\u751f\u6548\u3002</p>"},{"location":"faq.html#_5","title":"\u53ef\u4ee5\u540c\u65f6\u8fd0\u884c\u591a\u4e2a\u670d\u52a1\u5668\u5417\uff1f","text":"<p>\u53ef\u4ee5\u3002\u6bcf\u4e2a\u670d\u52a1\u5668\u662f\u72ec\u7acb\u7684\u5b50\u8fdb\u7a0b\uff0c\u4e92\u4e0d\u5e72\u6270\u3002\u5728\u4e3b\u83dc\u5355\u4e2d\u4f60\u53ef\u4ee5\u81ea\u7531\u5207\u6362\u4e0d\u540c\u670d\u52a1\u5668\u7684\u7ba1\u7406\u754c\u9762\uff0c\u4e00\u4e2a\u670d\u52a1\u5668\u8fd0\u884c\u4e2d\u65f6\u4e0d\u5f71\u54cd\u53e6\u4e00\u4e2a\u7684\u542f\u52a8\u548c\u64cd\u4f5c\u3002</p>"},{"location":"faq.html#_6","title":"\u5982\u4f55\u5907\u4efd\u670d\u52a1\u5668\uff1f","text":"<p>\u670d\u52a1\u5668\u6570\u636e\u5168\u90e8\u5b58\u50a8\u5728 <code>servers/&lt;\u670d\u52a1\u5668\u540d&gt;/</code> \u76ee\u5f55\u4e0b\u3002\u76f4\u63a5\u538b\u7f29\u8be5\u76ee\u5f55\u5373\u53ef\u5b8c\u6210\u5907\u4efd\u3002\u6062\u590d\u65f6\u901a\u8fc7\u300c\u5bfc\u5165\u538b\u7f29\u5305\u300d\u529f\u80fd\u8fd8\u539f\u3002</p>"},{"location":"faq.html#frpc","title":"\u5185\u7f51\u7a7f\u900f\u7684 frpc \u4e0b\u8f7d\u5931\u8d25\u600e\u4e48\u529e\uff1f","text":"<p>MSTL \u4ece OpenFrp \u5b98\u65b9\u955c\u50cf\u4e0b\u8f7d frpc\u3002\u5982\u679c\u4e0b\u8f7d\u5931\u8d25\uff1a</p> <ol> <li>\u68c0\u67e5\u7f51\u7edc\u662f\u5426\u80fd\u8bbf\u95ee OpenFrp \u955c\u50cf</li> <li>\u624b\u52a8\u4ece OpenFrp \u5b98\u7f51 \u4e0b\u8f7d\u5bf9\u5e94\u67b6\u6784\u7684 frpc</li> <li>\u653e\u5165\u9879\u76ee\u6839\u76ee\u5f55\u7684 <code>openfrp/</code> \u6587\u4ef6\u5939\u4e0b</li> </ol>"},{"location":"faq.html#bug","title":"\u9047\u5230 Bug \u6216\u8005\u6709\u529f\u80fd\u5efa\u8bae\uff1f","text":"<p>\u8bf7\u524d\u5f80 GitHub Issues \u63d0\u4ea4\u53cd\u9988\uff0c\u9644\u4e0a\uff1a</p> <ul> <li>\u64cd\u4f5c\u7cfb\u7edf\u7248\u672c</li> <li>Python \u7248\u672c\uff08<code>python --version</code>\uff09</li> <li>\u9519\u8bef\u65e5\u5fd7\uff08\u5982\u679c\u6709\uff09</li> <li>\u590d\u73b0\u6b65\u9aa4</li> </ul>"},{"location":"advanced/index.html","title":"\u8fdb\u9636","text":"<p>\u6df1\u5165\u7406\u89e3 MSTL \u7684\u5185\u90e8\u8bbe\u8ba1\u3002</p> \ud83c\udfd7\ufe0f \u9879\u76ee\u67b6\u6784 <p>\u6a21\u5757\u5212\u5206\u3001\u6570\u636e\u6d41\u3001\u8fd0\u884c\u6d41\u7a0b\u8be6\u89e3\u3002</p> \ud83d\udd27 \u4ece\u6e90\u7801\u6784\u5efa <p>\u672c\u5730\u5f00\u53d1\u73af\u5883\u642d\u5efa\u3001\u6253\u5305\u4e3a\u53ef\u6267\u884c\u6587\u4ef6\u3002</p>"},{"location":"advanced/architecture.html","title":"\u9879\u76ee\u67b6\u6784","text":""},{"location":"advanced/architecture.html#_2","title":"\u8bbe\u8ba1\u539f\u5219","text":"<p>MSTL \u9075\u5faa\u4e09\u6761\u6838\u5fc3\u539f\u5219\uff1a</p> <ul> <li>\u96f6\u5916\u90e8\u4f9d\u8d56\uff1a\u4ec5\u4f7f\u7528 Python \u6807\u51c6\u5e93\uff0c<code>pip install</code> \u4ec0\u4e48\u90fd\u4e0d\u9700\u8981</li> <li>\u6700\u5c0f\u60ca\u8bb6\uff1a\u529f\u80fd\u6309\u76f4\u89c9\u7ec4\u7ec7\uff0c\u914d\u7f6e\u9879\u5c3d\u91cf\u5c11\u4e14\u6709\u5408\u7406\u7684\u9ed8\u8ba4\u503c</li> <li>\u63a5\u53e3\u4f18\u5148\u4e8e\u5b9e\u73b0\uff1a\u63d2\u4ef6\u6e90\u3001\u6a21\u7ec4\u6e90\u3001Java \u68c0\u6d4b\u7b49\u6a21\u5757\u5747\u63d0\u4f9b\u7edf\u4e00\u7684\u62bd\u8c61\u63a5\u53e3\uff0c\u65b9\u4fbf\u6269\u5c55</li> </ul>"},{"location":"advanced/architecture.html#_3","title":"\u6a21\u5757\u7ed3\u6784","text":"<pre><code>mc-server-launcher/\n\u2502\n\u251c\u2500\u2500 start.py               # \u5165\u53e3\u70b9\n\u251c\u2500\u2500 config.py              # \u5168\u5c40\u914d\u7f6e\uff08config.json\uff09\u8bfb\u5199\n\u251c\u2500\u2500 clear.py               # \u7ec8\u7aef\u6e05\u5c4f\u5de5\u5177\uff08\u8de8\u5e73\u53f0\uff09\n\u2502\n\u251c\u2500\u2500 server_manager.py      # \u670d\u52a1\u5668\u5b9e\u4f8b\u76ee\u5f55\u7ba1\u7406\n\u251c\u2500\u2500 server_launcher.py     # \u670d\u52a1\u5668\u5b50\u8fdb\u7a0b\u542f\u52a8\u4e0e\u7ba1\u7406\n\u251c\u2500\u2500 download_msl.py        # MSL \u955c\u50cf\u6e90\u4ea4\u4e92 + \u591a\u7ebf\u7a0b\u4e0b\u8f7d\u5f15\u64ce\n\u2502\n\u251c\u2500\u2500 java_tools.py          # Java \u68c0\u6d4b\u3001JDK \u4e0b\u8f7d\u3001\u7248\u672c\u517c\u5bb9\u6821\u9a8c\n\u2502\n\u251c\u2500\u2500 plugin_sources.py      # \u63d2\u4ef6\u641c\u7d22\u4e0e\u4e0b\u8f7d\u62bd\u8c61\u5c42\n\u251c\u2500\u2500 mod_sources.py         # \u6a21\u7ec4\u641c\u7d22\u4e0e\u4e0b\u8f7d\u62bd\u8c61\u5c42\n\u2502\n\u251c\u2500\u2500 menu.py                # \u4ea4\u4e92\u5f0f\u83dc\u5355\u7cfb\u7edf\n\u251c\u2500\u2500 i18n.py                # \u56fd\u9645\u5316\u652f\u6301\n\u2502\n\u251c\u2500\u2500 openfrp/               # OpenFrp \u5185\u7f51\u7a7f\u900f\u6a21\u5757\n\u2502   \u2514\u2500\u2500 ...\n\u2502\n\u251c\u2500\u2500 locales/               # \u8bed\u8a00\u6587\u4ef6\n\u2502   \u251c\u2500\u2500 zh.json\n\u2502   \u251c\u2500\u2500 en.json\n\u2502   \u2514\u2500\u2500 ru.json\n\u2502\n\u2514\u2500\u2500 website/               # \u9879\u76ee\u5b98\u7f51\uff08\u72ec\u7acb HTML \u9875\u9762\uff09\n    \u251c\u2500\u2500 index.html\n    \u2514\u2500\u2500 lang.js\n</code></pre>"},{"location":"advanced/architecture.html#_4","title":"\u6a21\u5757\u804c\u8d23","text":""},{"location":"advanced/architecture.html#startpy","title":"\u542f\u52a8\u6d41\u7a0b\uff08<code>start.py</code>\uff09","text":"<p>\u542f\u52a8\u5668\u7684\u6267\u884c\u8def\u5f84\uff1a</p> <pre><code>start.py\n  \u2502\n  \u251c\u2500 \u6e05\u5c4f\n  \u251c\u2500 \u8bfb\u53d6 config.json\uff08config.py\uff09\n  \u251c\u2500 \u52a0\u8f7d\u56fd\u9645\u5316\uff08i18n.py\uff09\n  \u251c\u2500 \u521b\u5efa servers/ \u76ee\u5f55\n  \u2502\n  \u251c\u2500 \u9996\u6b21\u8fd0\u884c \u2192 \u5bfc\u5165/\u4e0b\u8f7d\u5411\u5bfc\n  \u2502\n  \u2514\u2500 \u5df2\u6709\u670d\u52a1\u5668 \u2192 \u5c55\u793a\u5217\u8868\n       \u2502\n       \u25bc \u9009\u4e2d\u670d\u52a1\u5668\n       \u2502\n       \u251c\u2500 Java \u89e3\u6790\uff08java_tools.py\uff09\n       \u2502   \u251c\u2500 \u68c0\u67e5\u7f13\u5b58\n       \u2502   \u251c\u2500 \u626b\u63cf\u7cfb\u7edf\u8def\u5f84\n       \u2502   \u251c\u2500 \u7248\u672c\u517c\u5bb9\u6821\u9a8c\n       \u2502   \u2514\u2500 \u5982\u7f3a\u5931 \u2192 \u81ea\u52a8\u4e0b\u8f7d GraalVM JDK\n       \u2502\n       \u251c\u2500 \u542f\u52a8\u5b50\u8fdb\u7a0b\uff08server_launcher.py\uff09\n       \u2502   \u251c\u2500 \u6784\u5efa JVM \u542f\u52a8\u547d\u4ee4\n       \u2502   \u251c\u2500 \u521b\u5efa\u5b50\u8fdb\u7a0b\n       \u2502   \u2514\u2500 \u6355\u83b7 stdout\n       \u2502\n       \u2514\u2500 \u63a7\u5236\u53f0\u4ea4\u4e92\n           \u251c\u2500 \u6307\u4ee4\u900f\u4f20 \u2192 \u670d\u52a1\u5668 stdin\n           \u2514\u2500 \u65e5\u5fd7\u8f93\u51fa \u2190 \u670d\u52a1\u5668 stdout\n</code></pre>"},{"location":"advanced/architecture.html#download_mslpy","title":"\u591a\u7ebf\u7a0b\u4e0b\u8f7d\u5f15\u64ce\uff08<code>download_msl.py</code>\uff09","text":"<p>\u4e0b\u8f7d\u5f15\u64ce\u662f\u591a\u4e2a\u529f\u80fd\u6a21\u5757\u7684\u5e95\u5c42\u57fa\u7840\u8bbe\u65bd\uff1a</p> <pre><code>\u8bf7\u6c42 URL\n  \u2502\n  \u251c\u2500 HEAD \u8bf7\u6c42\u68c0\u6d4b Range \u652f\u6301\n  \u2502   \u251c\u2500 \u652f\u6301 \u2192 \u5206\u5272\u4e3a 16 \u5757\uff0c\u5e76\u53d1\u4e0b\u8f7d\n  \u2502   \u2502          \u6bcf\u5757\u5199\u5165\u4e34\u65f6\u6587\u4ef6\uff0c\u5b8c\u6210\u540e\u5408\u5e76\n  \u2502   \u2514\u2500 \u4e0d\u652f\u6301 \u2192 \u5355\u7ebf\u7a0b\u76f4\u63a5\u4e0b\u8f7d\n  \u2502\n  \u2514\u2500 \u8fdb\u5ea6\u53cd\u9988\uff08\u4e0b\u8f7d\u91cf / \u603b\u5927\u5c0f / \u901f\u5ea6\uff09\n</code></pre>"},{"location":"advanced/architecture.html#_5","title":"\u63d2\u4ef6 / \u6a21\u7ec4\u641c\u7d22\u67b6\u6784","text":"<p>\u63d2\u4ef6\u548c\u6a21\u7ec4\u7684\u641c\u7d22\u6a21\u5757\u91c7\u7528\u4e86\u76f8\u4f3c\u7684\u8bbe\u8ba1\u6a21\u5f0f\uff1a</p> <pre><code>\u7edf\u4e00\u641c\u7d22\u63a5\u53e3\n  \u2502\n  \u251c\u2500 \u5e76\u884c\u8c03\u7528\u591a\u4e2a\u6e90\n  \u2502   \u251c\u2500 SpigotMC (Spiget)\n  \u2502   \u251c\u2500 Modrinth\n  \u2502   \u251c\u2500 Hangar\n  \u2502   \u2514\u2500 CurseForge\n  \u2502\n  \u251c\u2500 \u5408\u5e76\u7ed3\u679c\u5217\u8868\n  \u251c\u2500 \u6309\u4e0b\u8f7d\u91cf\u964d\u5e8f\u6392\u5e8f\n  \u2514\u2500 \u5c55\u793a\u7ed9\u7528\u6237\n</code></pre>"},{"location":"advanced/architecture.html#_6","title":"\u6570\u636e\u6d41","text":"<pre><code>\u78c1\u76d8 (config.json / .server.json)\n  \u2502\n  \u251c\u2500 start.py \u8bfb\u53d6 \u2192 \u6784\u5efa\u83dc\u5355\n  \u2502\n  \u2514\u2500 \u7528\u6237\u64cd\u4f5c\n       \u2502\n       \u251c\u2500 \u914d\u7f6e\u4fee\u6539 \u2192 config.py \u2192 \u5199\u5165\u78c1\u76d8\n       \u251c\u2500 \u542f\u52a8\u670d\u52a1\u5668 \u2192 server_launcher.py \u2192 \u5b50\u8fdb\u7a0b\n       \u251c\u2500 \u641c\u7d22\u63d2\u4ef6 \u2192 plugin_sources.py \u2192 \u7f51\u7edc API \u2192 \u4e0b\u8f7d \u2192 plugins/ \u76ee\u5f55\n       \u2514\u2500 \u96a7\u9053\u7ed1\u5b9a \u2192 openfrp/ \u2192 frpc \u5b50\u8fdb\u7a0b\n</code></pre>"},{"location":"advanced/build.html","title":"\u4ece\u6e90\u7801\u6784\u5efa","text":"<p>MSTL \u672c\u8eab\u662f\u7eaf Python \u811a\u672c\uff0c\u76f4\u63a5\u8fd0\u884c\u5373\u53ef\u3002\u5982\u679c\u4f60\u9700\u8981\u6253\u5305\u4e3a\u72ec\u7acb\u7684\u53ef\u6267\u884c\u6587\u4ef6\uff0c\u4ee5\u4e0b\u662f\u4e00\u4e9b\u53c2\u8003\u3002</p>"},{"location":"advanced/build.html#_2","title":"\u672c\u5730\u5f00\u53d1","text":""},{"location":"advanced/build.html#_3","title":"\u514b\u9686\u4ed3\u5e93","text":"<pre><code>git clone https://github.com/yzsyzdy/mc-server-launcher.git\ncd mc-server-launcher\n</code></pre>"},{"location":"advanced/build.html#_4","title":"\u76f4\u63a5\u8fd0\u884c","text":"<pre><code>python start.py\n</code></pre> <p>MSTL \u6ca1\u6709\u7b2c\u4e09\u65b9\u4f9d\u8d56\uff0c\u4e0d\u9700\u8981\u521b\u5efa\u865a\u62df\u73af\u5883\u6216\u5b89\u88c5\u4efb\u4f55\u5305\u3002</p>"},{"location":"advanced/build.html#_5","title":"\u4ee3\u7801\u98ce\u683c","text":"<p>\u9879\u76ee\u4fdd\u6301\u76f8\u5bf9\u7b80\u6d01\u7684\u98ce\u683c\uff0c\u4e3b\u8981\u9075\u5faa\uff1a</p> <ul> <li>\u7c7b\u578b\u6ce8\u89e3\uff08<code>typing</code> \u6a21\u5757\uff09</li> <li>\u51fd\u6570\u548c\u7c7b\u6709 docstring</li> <li>\u914d\u7f6e\u6587\u4ef6\u7edf\u4e00\u901a\u8fc7 <code>config.py</code> \u8bfb\u5199</li> </ul>"},{"location":"advanced/build.html#_6","title":"\u6253\u5305\u4e3a\u53ef\u6267\u884c\u6587\u4ef6","text":""},{"location":"advanced/build.html#nuitka","title":"\u4f7f\u7528 Nuitka\uff08\u63a8\u8350\uff09","text":"<p>Nuitka \u53ef\u4ee5\u5c06 Python \u811a\u672c\u7f16\u8bd1\u4e3a\u72ec\u7acb\u7684\u53ef\u6267\u884c\u6587\u4ef6\uff0c\u542f\u52a8\u901f\u5ea6\u6bd4 PyInstaller \u66f4\u5feb\u3002</p> <pre><code>pip install nuitka\npython -m nuitka --standalone --onefile start.py\n</code></pre> <p>\u7f16\u8bd1\u4ea7\u7269\u4e3a <code>start.exe</code>\uff08Windows\uff09\u6216 <code>start</code>\uff08Linux\uff09\uff0c\u4e0d\u4f9d\u8d56 Python \u73af\u5883\u3002</p>"},{"location":"advanced/build.html#pyinstaller","title":"\u4f7f\u7528 PyInstaller","text":"<pre><code>pip install pyinstaller\npyinstaller --onefile start.py\n</code></pre> <p>\u7f16\u8bd1\u4ea7\u7269\u5728 <code>dist/start.exe</code>\u3002</p>"},{"location":"advanced/build.html#_7","title":"\u56fd\u9645\u5316\u8d21\u732e","text":"<p>\u5982\u679c\u4f60\u60f3\u6dfb\u52a0\u65b0\u7684\u8bed\u8a00\u652f\u6301\uff1a</p> <ol> <li>\u5728 <code>locales/</code> \u76ee\u5f55\u4e0b\u521b\u5efa <code>{\u8bed\u8a00\u4ee3\u7801}.json</code></li> <li>\u53c2\u8003 <code>zh.json</code> \u7684\u952e\u7ed3\u6784\u8fdb\u884c\u7ffb\u8bd1</li> <li>\u5728 <code>i18n.py</code> \u7684 <code>lang_names</code> \u5b57\u5178\u4e2d\u6dfb\u52a0\u8bed\u8a00\u663e\u793a\u540d\u79f0</li> </ol> <p>\u76ee\u524d\u652f\u6301\u7684\u8bed\u8a00\uff1a</p> \u4ee3\u7801 \u8bed\u8a00 \u7ef4\u62a4\u8005 <code>zh</code> \u4e2d\u6587 yzsyzdy <code>en</code> English yzsyzdy <code>ru</code> \u0420\u0443\u0441\u0441\u043a\u0438\u0439 \u2014"},{"location":"advanced/build.html#_8","title":"\u8d21\u732e\u6307\u5357","text":"<ol> <li>Fork \u9879\u76ee</li> <li>\u521b\u5efa\u529f\u80fd\u5206\u652f\uff1a<code>git checkout -b feature/my-feature</code></li> <li>\u63d0\u4ea4\u6539\u52a8\uff1a<code>git commit -am 'Add some feature'</code></li> <li>\u63a8\u9001\u5230\u5206\u652f\uff1a<code>git push origin feature/my-feature</code></li> <li>\u63d0\u4ea4 Pull Request</li> </ol> <p>\u5c0f\u5efa\u8bae\uff1a</p> <ul> <li>\u4fdd\u6301\u96f6\u5916\u90e8\u4f9d\u8d56\u539f\u5219</li> <li>\u65b0\u589e\u529f\u80fd\u8bf7\u6dfb\u52a0\u5bf9\u5e94\u7684\u83dc\u5355\u9879\u548c\u56fd\u9645\u5316\u7ffb\u8bd1</li> <li>Windows \u548c Linux \u53cc\u5e73\u53f0\u517c\u5bb9</li> </ul>"},{"location":"features/index.html","title":"\u529f\u80fd\u8be6\u89e3","text":"<p>MSTL \u7684\u6838\u5fc3\u529f\u80fd\u9010\u4e00\u8be6\u89e3\u3002</p> \ud83e\udde9 \u63d2\u4ef6\u7ba1\u7406 <p>\u591a\u6e90\u641c\u7d22\u3001\u4e00\u952e\u4e0b\u8f7d\u3001\u542f\u7528/\u7981\u7528\uff0c\u652f\u6301 SpigotMC\u3001Modrinth\u3001Hangar\u3002</p> \ud83d\udce6 \u6a21\u7ec4\u7ba1\u7406 <p>Modrinth \u548c CurseForge \u53cc\u6e90\u641c\u7d22\uff0c\u81ea\u52a8\u6309 MC \u7248\u672c\u548c\u52a0\u8f7d\u5668\u8fc7\u6ee4\u3002</p> \ud83d\ude87 \u5185\u7f51\u7a7f\u900f <p>\u96c6\u6210 OpenFrp\uff0c\u81ea\u52a8\u4e0b\u8f7d frpc\uff0c\u96a7\u9053\u968f\u670d\u52a1\u5668\u542f\u505c\u3002</p>"},{"location":"features/mod-management.html","title":"\u6a21\u7ec4\u7ba1\u7406","text":"<p>MSTL \u652f\u6301\u5728\u591a\u4e2a\u6a21\u7ec4\u5e73\u53f0\u641c\u7d22\u5e76\u4e0b\u8f7d\u6a21\u7ec4\uff0c\u81ea\u52a8\u5339\u914d\u5f53\u524d\u670d\u52a1\u5668\u7684 MC \u7248\u672c\u548c\u52a0\u8f7d\u5668\u3002</p>"},{"location":"features/mod-management.html#_2","title":"\u652f\u6301\u7684\u6a21\u7ec4\u6e90","text":"\u6e90 API Key \u8bf4\u660e Modrinth \u4e0d\u9700\u8981 \u6700\u5927\u7684 Fabric/Quilt/Forge \u6a21\u7ec4\u5e73\u53f0\uff0c\u539f\u751f\u652f\u6301\u4e2d\u6587\u641c\u7d22 CurseForge \u9700\u8981\uff08\u53ef\u9009\uff09 \u4f20\u7edf\u6a21\u7ec4\u5e73\u53f0\uff0c\u9700\u5728 <code>config.json</code> \u4e2d\u914d\u7f6e API key"},{"location":"features/mod-management.html#curseforge-api-key","title":"\u914d\u7f6e CurseForge API Key","text":"<p>\u5982\u679c\u9700\u8981\u4f7f\u7528 CurseForge \u641c\u7d22\uff1a</p> <ol> <li>\u524d\u5f80 CurseForge Console \u6ce8\u518c\u5e76\u7533\u8bf7 API key</li> <li>\u5728\u9879\u76ee\u6839\u76ee\u5f55\u7684 <code>config.json</code> \u4e2d\u586b\u5165\uff1a</li> </ol> <pre><code>{\n  \"curseforge_api_key\": \"your-api-key-here\"\n}\n</code></pre> <p>Modrinth \u65e0\u9700\u914d\u7f6e</p> <p>Modrinth \u641c\u7d22\u4e0d\u9700\u8981\u4efb\u4f55 API key\uff0c\u5f00\u7bb1\u5373\u7528\u3002</p>"},{"location":"features/mod-management.html#_3","title":"\u641c\u7d22\u6a21\u7ec4","text":"<p>\u5728\u4e3b\u83dc\u5355\u9009\u62e9\u670d\u52a1\u5668 \u2192 \u8fdb\u5165\u6a21\u7ec4\u7ba1\u7406 \u2192 \u8f93\u5165\u5173\u952e\u8bcd\u641c\u7d22\u3002</p> <p>MSTL \u4f1a\u81ea\u52a8\uff1a</p> <ol> <li>\u8bfb\u53d6\u5f53\u524d\u670d\u52a1\u5668\u7684 MC \u7248\u672c\u53f7\uff08\u5982 <code>1.21.1</code>\uff09\u548c\u6a21\u7ec4\u52a0\u8f7d\u5668\u7c7b\u578b\uff08\u5982 Fabric\uff09</li> <li>\u5728 Modrinth\uff08\u548c CurseForge\uff0c\u5982\u5df2\u914d\u7f6e Key\uff09\u4e2d\u641c\u7d22</li> <li>\u81ea\u52a8\u8fc7\u6ee4\u51fa\u5339\u914d\u7248\u672c\u548c\u52a0\u8f7d\u5668\u7684\u6a21\u7ec4</li> <li>\u5982\u679c\u7ed3\u679c\u592a\u5c11\uff0c\u81ea\u52a8\u653e\u5bbd\u641c\u7d22\u8303\u56f4</li> </ol> <pre><code>\u641c\u7d22 \"jei\" (Fabric \u00b7 1.21.1):\n\n[Modrinth] \u627e\u5230 12 \u4e2a\u7ed3\u679c\uff1a\n 1. JEI (Just Enough Items) \u2014 1.21.1-fabric \u2014 12,345,678 \u4e0b\u8f7d\n 2. JEI Integration \u2014 1.21.1-fabric \u2014 234,567 \u4e0b\u8f7d\n...\n</code></pre>"},{"location":"features/mod-management.html#_4","title":"\u4e2d\u6587\u641c\u7d22","text":"<p>Modrinth \u539f\u751f\u652f\u6301 Unicode \u67e5\u8be2\u3002\u5982\u679c\u6a21\u7ec4\u7684\u7b80\u4ecb\u5305\u542b\u4e2d\u6587\u5173\u952e\u8bcd\uff0c\u76f4\u63a5\u7528\u4e2d\u6587\u641c\u7d22\u5373\u53ef\u3002\u82f1\u6587\u5173\u952e\u8bcd\u7684\u641c\u7d22\u7ed3\u679c\u901a\u5e38\u66f4\u5168\u9762\u3002</p>"},{"location":"features/mod-management.html#_5","title":"\u4e0b\u8f7d","text":"<p>\u9009\u4e2d\u7ed3\u679c\u7f16\u53f7\u540e\uff1a</p> <ol> <li>\u83b7\u53d6\u5339\u914d\u7248\u672c\u7684\u6700\u65b0 jar</li> <li>16 \u7ebf\u7a0b\u5e76\u53d1\u4e0b\u8f7d</li> <li>\u81ea\u52a8\u653e\u5165\u670d\u52a1\u5668\u7684 <code>mods/</code> \u76ee\u5f55</li> <li>\u63d0\u793a\u91cd\u542f\u52a0\u8f7d</li> </ol>"},{"location":"features/mod-management.html#_6","title":"\u672c\u5730\u5bfc\u5165\u4e0e\u542f\u7528/\u7981\u7528","text":"<p>\u64cd\u4f5c\u65b9\u5f0f\u4e0e\u63d2\u4ef6\u7ba1\u7406\u4e00\u81f4\uff1a</p> <ul> <li>\u5bfc\u5165\u672c\u5730 jar\uff1a\u9009\u62e9 <code>.jar</code> \u6587\u4ef6\uff0c\u590d\u5236\u5230 <code>mods/</code></li> <li>\u7981\u7528\uff1a<code>mods/\u6a21\u7ec4.jar</code> \u2192 <code>mods/\u6a21\u7ec4.jar.disabled</code></li> <li>\u542f\u7528\uff1a\u53cd\u5411\u64cd\u4f5c</li> </ul>"},{"location":"features/plugin-management.html","title":"\u63d2\u4ef6\u7ba1\u7406","text":"<p>MSTL \u96c6\u6210\u4e86\u591a\u4e2a\u63d2\u4ef6\u6e90\u7684\u641c\u7d22\u4e0e\u4e0b\u8f7d\u529f\u80fd\u3002</p>"},{"location":"features/plugin-management.html#_2","title":"\u652f\u6301\u7684\u63d2\u4ef6\u6e90","text":"\u6e90 API \u662f\u5426\u9700\u8981 Key \u8bf4\u660e SpigotMC Spiget API \u5426 \u6700\u5927\u7684 Bukkit/Spigot \u63d2\u4ef6\u793e\u533a Modrinth Modrinth API \u5426 \u652f\u6301 Fabric/Quilt \u548c Bukkit \u63d2\u4ef6 Hangar Hangar API \u5426 PaperMC \u5b98\u65b9\u63d2\u4ef6\u5e73\u53f0"},{"location":"features/plugin-management.html#_3","title":"\u641c\u7d22\u63d2\u4ef6","text":"<p>\u5728\u4e3b\u83dc\u5355\u9009\u62e9\u670d\u52a1\u5668 \u2192 \u8fdb\u5165\u63d2\u4ef6\u7ba1\u7406 \u2192 \u8f93\u5165\u5173\u952e\u8bcd\u641c\u7d22\u3002</p> <p>\u7cfb\u7edf\u4f1a\u81ea\u52a8\u5728\u4e09\u4e2a\u6e90\u4e2d\u5e76\u884c\u641c\u7d22\uff0c\u7ed3\u679c\u6309\u4e0b\u8f7d\u91cf\u4ece\u9ad8\u5230\u4f4e\u6392\u5e8f\u5c55\u793a\uff1a</p> <pre><code>[SpigotMC] \u627e\u5230 8 \u4e2a\u7ed3\u679c\uff1a\n 1. EssentialsX (2,341,592 \u4e0b\u8f7d) \u2014 v2.21.0\n 2. LuckPerms (1,892,333 \u4e0b\u8f7d) \u2014 v5.4.151\n 3. Vault (1,245,678 \u4e0b\u8f7d) \u2014 v1.7.3\n...\n[Modrinth] \u627e\u5230 5 \u4e2a\u7ed3\u679c\uff1a\n 7. Spark (890,234 \u4e0b\u8f7d) \u2014 v1.10.109\n...\n</code></pre>"},{"location":"features/plugin-management.html#_4","title":"\u641c\u7d22\u6280\u5de7","text":"<ul> <li>\u5173\u952e\u8bcd\u8d8a\u7cbe\u786e\u8d8a\u597d\uff08\u5982 <code>EssentialsX</code> \u800c\u975e <code>ess</code>\uff09</li> <li>\u90e8\u5206\u63d2\u4ef6\u5728 SpigotMC \u4e0a\u53ef\u80fd\u88ab\u6807\u8bb0\u4e3a\u5916\u90e8\u6258\u7ba1\uff08\u5982 GitHub\uff09\uff0cMSTL \u4f1a\u901a\u8fc7 GitHub API \u81ea\u52a8\u83b7\u53d6 jar</li> </ul>"},{"location":"features/plugin-management.html#_5","title":"\u4e0b\u8f7d\u4e0e\u5b89\u88c5","text":"<p>\u9009\u4e2d\u641c\u7d22\u7ed3\u679c\u4e2d\u7684\u7f16\u53f7\uff0cMSTL \u4f1a\u81ea\u52a8\uff1a</p> <ol> <li>\u83b7\u53d6\u8be5\u63d2\u4ef6\u6700\u65b0\u7248\u672c\u7684 jar \u4e0b\u8f7d\u94fe\u63a5</li> <li>\u4f7f\u7528 16 \u7ebf\u7a0b\u5e76\u53d1\u5206\u5757\u4e0b\u8f7d</li> <li>\u5c06 jar \u653e\u5165\u670d\u52a1\u5668\u7684 <code>plugins/</code> \u76ee\u5f55</li> <li>\u5b8c\u6210\u540e\u63d0\u793a\u91cd\u542f\u670d\u52a1\u5668\u4ee5\u52a0\u8f7d</li> </ol>"},{"location":"features/plugin-management.html#_6","title":"\u542f\u7528\u4e0e\u7981\u7528","text":"<p>MSTL \u901a\u8fc7\u91cd\u547d\u540d jar \u6587\u4ef6\u6765\u63a7\u5236\u63d2\u4ef6\u7684\u542f\u7528\u72b6\u6001\uff1a</p> <ul> <li>\u7981\u7528\uff1a<code>plugins/\u63d2\u4ef6\u540d.jar</code> \u2192 <code>plugins/\u63d2\u4ef6\u540d.jar.disabled</code></li> <li>\u542f\u7528\uff1a<code>plugins/\u63d2\u4ef6\u540d.jar.disabled</code> \u2192 <code>plugins/\u63d2\u4ef6\u540d.jar</code></li> </ul> <p>\u8fd9\u4e0d\u9700\u8981\u5220\u9664\u6587\u4ef6\uff0c\u968f\u65f6\u53ef\u4ee5\u6062\u590d\u3002</p>"},{"location":"features/plugin-management.html#_7","title":"\u672c\u5730\u5bfc\u5165","text":"<p>\u5982\u679c\u4f60\u624b\u5934\u6709\u63d2\u4ef6 jar \u6587\u4ef6\uff1a</p> <ol> <li>\u5728\u63d2\u4ef6\u7ba1\u7406\u4e2d\u9009\u62e9\u300c\u5bfc\u5165\u672c\u5730 jar\u300d</li> <li>\u6d4f\u89c8\u5e76\u9009\u4e2d <code>.jar</code> \u6587\u4ef6</li> <li>\u6587\u4ef6\u4f1a\u81ea\u52a8\u590d\u5236\u5230\u670d\u52a1\u5668\u7684 <code>plugins/</code> \u76ee\u5f55</li> </ol> <p>\u6258\u7ba1\u5728 GitHub \u7684\u63d2\u4ef6</p> <p>\u90e8\u5206\u63d2\u4ef6\u7684\u4e0b\u8f7d\u9875\u9762\u6307\u5411 GitHub Releases\u3002MSTL \u901a\u8fc7 GitHub API \u89e3\u6790\u6700\u65b0\u7684 Release \u8d44\u4ea7\uff0c\u81ea\u52a8\u627e\u5230\u5339\u914d\u7684 jar \u6587\u4ef6\u8fdb\u884c\u4e0b\u8f7d\u3002</p>"},{"location":"features/tunnel.html","title":"\u5185\u7f51\u7a7f\u900f\uff08OpenFrp\uff09","text":"<p>MSTL \u96c6\u6210\u4e86 OpenFrp \u5185\u7f51\u7a7f\u900f\u529f\u80fd\uff0c\u53ef\u4ee5\u4e3a\u4f60\u7684 Minecraft \u670d\u52a1\u5668\u521b\u5efa\u516c\u7f51 TCP \u96a7\u9053\u3002</p>"},{"location":"features/tunnel.html#_1","title":"\u524d\u7f6e\u51c6\u5907","text":"<ol> <li>\u6ce8\u518c OpenFrp \u8d26\u53f7</li> <li>\u5728 OpenFrp \u63a7\u5236\u53f0 \u83b7\u53d6\u4f60\u7684 \u7528\u6237 token</li> </ol>"},{"location":"features/tunnel.html#_2","title":"\u4f7f\u7528\u6d41\u7a0b","text":""},{"location":"features/tunnel.html#_3","title":"\u7b2c\u4e00\u6b65\uff1a\u67e5\u770b\u96a7\u9053\u5217\u8868","text":"<ol> <li>\u5728\u4e3b\u83dc\u5355\u8fdb\u5165 OpenFrp\uff08\u9009\u9879 6\uff09</li> <li>\u9009\u62e9 \u67e5\u770b\u96a7\u9053\u5217\u8868</li> <li>\u8f93\u5165\u4f60\u7684 OpenFrp token</li> <li>MSTL \u4f1a\u8c03\u7528 OpenFrp API \u5217\u51fa\u4f60\u8d26\u53f7\u4e0b\u7684\u6240\u6709\u96a7\u9053</li> </ol> <pre><code>OpenFrp \u96a7\u9053\u5217\u8868\uff1a\n[1] \u751f\u5b58\u670d (Node: \u4e0a\u6d77-1 \u2192 Localhost:25565) \u2014 \u8fd0\u884c\u4e2d\n[2] \u521b\u9020\u670d (Node: \u5e7f\u5dde-2 \u2192 Localhost:25566) \u2014 \u5df2\u505c\u6b62\n</code></pre>"},{"location":"features/tunnel.html#_4","title":"\u7b2c\u4e8c\u6b65\uff1a\u7ed1\u5b9a\u96a7\u9053\u5230\u670d\u52a1\u5668","text":"<ol> <li>\u5728 OpenFrp \u83dc\u5355\u4e2d\u9009\u62e9 \u7ed1\u5b9a\u96a7\u9053\u5230\u670d\u52a1\u5668</li> <li>\u9009\u62e9\u76ee\u6807\u96a7\u9053</li> <li>\u9009\u62e9\u8981\u7ed1\u5b9a\u7684\u672c\u5730\u670d\u52a1\u5668\u5b9e\u4f8b</li> <li>\u7ed1\u5b9a\u540e\uff0c\u542f\u52a8\u8be5\u670d\u52a1\u5668\u65f6 frpc \u4f1a\u81ea\u52a8\u8ddf\u968f\u542f\u52a8</li> </ol>"},{"location":"features/tunnel.html#_5","title":"\u7b2c\u4e09\u6b65\uff1a\u542f\u52a8","text":"<p>\u7ed1\u5b9a\u5b8c\u6210\u540e\uff0c\u53ea\u9700\u6b63\u5e38\u542f\u52a8\u670d\u52a1\u5668\u3002MSTL \u81ea\u52a8\u5904\u7406\u4ee5\u4e0b\u6d41\u7a0b\uff1a</p> <pre><code>\u542f\u52a8\u670d\u52a1\u5668\u8fdb\u7a0b\n  \u2514\u2500 \u68c0\u6d4b\u8be5\u670d\u52a1\u5668\u662f\u5426\u7ed1\u5b9a\u4e86\u96a7\u9053\n       \u2514\u2500 \u662f \u2192 \u68c0\u6d4b frpc \u662f\u5426\u5b58\u5728\n            \u251c\u2500 \u4e0d\u5b58\u5728 \u2192 \u81ea\u52a8\u4e0b\u8f7d\u5339\u914d\u7cfb\u7edf\u67b6\u6784\u7684 frpc\n            \u2514\u2500 \u5b58\u5728 \u2192 \u542f\u52a8 frpc \u96a7\u9053\u8fdb\u7a0b\n</code></pre>"},{"location":"features/tunnel.html#frpc","title":"frpc \u81ea\u52a8\u7ba1\u7406","text":"<p>MSTL \u4f1a\u81ea\u52a8\uff1a</p> <ul> <li>\u68c0\u6d4b\u7cfb\u7edf\u67b6\u6784\uff1a\u81ea\u52a8\u8bc6\u522b Windows / Linux\u3001x86_64 / arm64</li> <li>\u4e0b\u8f7d frpc\uff1a\u4ece OpenFrp \u955c\u50cf\u4e0b\u8f7d\u5bf9\u5e94\u67b6\u6784\u7684 frpc \u4e8c\u8fdb\u5236\u6587\u4ef6</li> <li>\u81ea\u52a8\u542f\u505c\uff1a\u670d\u52a1\u5668\u542f\u52a8\u65f6\u81ea\u52a8\u62c9\u8d77 frpc\uff0c\u670d\u52a1\u5668\u505c\u6b62\u65f6\u81ea\u52a8\u5173\u95ed frpc</li> </ul> <p>\u65e0\u9700\u624b\u52a8\u4e0b\u8f7d\u6216\u914d\u7f6e frpc\u3002</p>"},{"location":"features/tunnel.html#_6","title":"\u521b\u5efa\u65b0\u96a7\u9053","text":"<p>\u5728 OpenFrp \u83dc\u5355\u4e2d\u9009\u62e9\u521b\u5efa\u96a7\u9053\uff0c\u6309\u5411\u5bfc\u586b\u5165\uff1a</p> <ul> <li>\u96a7\u9053\u540d\u79f0</li> <li>\u9009\u62e9\u8282\u70b9</li> <li>\u672c\u5730\u7aef\u53e3\uff08\u5982 <code>25565</code>\uff09</li> <li>\u8fdc\u7a0b\u7aef\u53e3\u7c7b\u578b\uff08TCP\uff09</li> </ul> <p>\u521b\u5efa\u6210\u529f\u540e\u4f1a\u81ea\u52a8\u5237\u65b0\u96a7\u9053\u5217\u8868\u3002</p>"},{"location":"guide/index.html","title":"\u4f7f\u7528\u6307\u5357","text":"<p>\u8fd9\u91cc\u5305\u542b\u4e86 MSTL \u4ece\u5b89\u88c5\u5230\u65e5\u5e38\u4f7f\u7528\u7684\u5168\u90e8\u64cd\u4f5c\u8bf4\u660e\u3002</p> \ud83d\ude80 \u5feb\u901f\u5f00\u59cb <p>\u4ece\u96f6\u5f00\u59cb\u5feb\u901f\u4e0a\u624b\uff1a\u4e0b\u8f7d\u3001\u542f\u52a8\u3001\u521b\u5efa\u7b2c\u4e00\u4e2a\u670d\u52a1\u5668\u3002</p> \ud83d\udda5 \u670d\u52a1\u5668\u7ba1\u7406 <p>\u591a\u5b9e\u4f8b\u7ba1\u7406\u3001\u542f\u52a8/\u505c\u6b62\u3001\u538b\u7f29\u5305\u5bfc\u5165\u3001\u63a7\u5236\u53f0\u64cd\u4f5c\u3002</p> \u2699\ufe0f \u914d\u7f6e\u8bf4\u660e <p>\u5168\u5c40\u914d\u7f6e\u4e0e\u670d\u52a1\u5668\u914d\u7f6e\u7684\u5b57\u6bb5\u8be6\u89e3\u3002</p> <p>\u5982\u679c\u4f60\u8fd8\u4e0d\u719f\u6089 MSTL\uff0c\u5efa\u8bae\u4ece \u5feb\u901f\u5f00\u59cb \u8bfb\u8d77\u3002</p>"},{"location":"guide/configuration.html","title":"\u914d\u7f6e\u8bf4\u660e","text":"<p>MSTL \u7684\u914d\u7f6e\u5206\u4e3a\u4e24\u5c42\uff1a\u5168\u5c40\u914d\u7f6e\u548c\u670d\u52a1\u5668\u914d\u7f6e\u3002</p>"},{"location":"guide/configuration.html#configjson","title":"\u5168\u5c40\u914d\u7f6e\uff08config.json\uff09","text":"<p>\u4f4d\u4e8e\u9879\u76ee\u6839\u76ee\u5f55\uff0c\u7531 <code>start.py</code> \u9996\u6b21\u8fd0\u884c\u65f6\u81ea\u52a8\u521b\u5efa\u3002</p> <pre><code>{\n  \"java_path\": null,\n  \"interactive\": true,\n  \"language\": \"\",\n  \"curseforge_api_key\": \"\"\n}\n</code></pre> \u5b57\u6bb5 \u7c7b\u578b \u9ed8\u8ba4\u503c \u8bf4\u660e <code>java_path</code> <code>string \\| null</code> <code>null</code> \u6307\u5b9a Java \u53ef\u6267\u884c\u6587\u4ef6\u8def\u5f84\u3002<code>null</code> \u8868\u793a\u81ea\u52a8\u68c0\u6d4b <code>interactive</code> <code>boolean</code> <code>true</code> \u662f\u5426\u542f\u7528\u63a7\u5236\u53f0\u4ea4\u4e92\u6a21\u5f0f\uff08\u5411\u670d\u52a1\u5668\u8f93\u5165\u6307\u4ee4\uff09 <code>language</code> <code>string</code> <code>\"\"</code> \u754c\u9762\u8bed\u8a00\u4ee3\u7801\uff08<code>\"zh\"</code> / <code>\"en\"</code> / <code>\"ru\"</code>\uff09\u3002\u7a7a\u5b57\u7b26\u4e32\u65f6\u81ea\u52a8\u68c0\u6d4b\u7cfb\u7edf\u8bed\u8a00 <code>curseforge_api_key</code> <code>string</code> <code>\"\"</code> CurseForge API key\u3002\u4e0d\u586b\u5219\u65e0\u6cd5\u641c\u7d22 CurseForge \u6a21\u7ec4 <p>language \u5b57\u6bb5</p> <p>\u8bbe\u4e3a <code>\"\"</code> \u65f6\u81ea\u52a8\u6839\u636e\u64cd\u4f5c\u7cfb\u7edf\u8bed\u8a00\u9009\u62e9\u3002\u76ee\u524d\u652f\u6301\u4e2d\u6587\uff08<code>zh</code>\uff09\u3001\u82f1\u6587\uff08<code>en</code>\uff09\u548c\u4fc4\u8bed\uff08<code>ru</code>\uff09\u3002</p>"},{"location":"guide/configuration.html#serverjson","title":"\u670d\u52a1\u5668\u914d\u7f6e\uff08.server.json\uff09","text":"<p>\u6bcf\u4e2a\u670d\u52a1\u5668\u5b9e\u4f8b\u72ec\u7acb\u914d\u7f6e\uff0c\u6587\u4ef6\u4f4d\u4e8e <code>servers/&lt;\u670d\u52a1\u5668\u540d&gt;/.server.json</code>\u3002</p> <pre><code>{\n  \"name\": \"\u751f\u5b58\u670d1\",\n  \"mc_version\": \"1.21.1\",\n  \"jar\": \"leaves.jar\",\n  \"java_path\": null,\n  \"min_mem\": \"2G\",\n  \"max_mem\": \"8G\",\n  \"extra_jvm_args\": [],\n  \"extra_server_args\": []\n}\n</code></pre>"},{"location":"guide/configuration.html#_2","title":"\u5b57\u6bb5\u8be6\u89e3","text":"\u5b57\u6bb5 \u7c7b\u578b \u5fc5\u586b \u8bf4\u660e <code>name</code> <code>string</code> \u662f \u670d\u52a1\u5668\u663e\u793a\u540d\u79f0 <code>mc_version</code> <code>string</code> \u662f Minecraft \u7248\u672c\u53f7\uff0c\u5982 <code>1.21.1</code> <code>jar</code> <code>string</code> \u662f \u670d\u52a1\u7aef\u6838\u5fc3 jar \u7684\u6587\u4ef6\u540d\uff08\u5982 <code>paper-1.21.1.jar</code>\uff09 <code>java_path</code> <code>string \\| null</code> \u5426 \u8be5\u670d\u52a1\u5668\u4e13\u7528\u7684 Java \u8def\u5f84\u3002<code>null</code> \u5219\u4f7f\u7528\u5168\u5c40 Java <code>min_mem</code> <code>string</code> \u5426 \u6700\u5c0f\u5185\u5b58\uff0c\u652f\u6301 <code>G</code> / <code>M</code> \u5355\u4f4d\uff0c\u5982 <code>2G</code>\u3001<code>1024M</code> <code>max_mem</code> <code>string</code> \u5426 \u6700\u5927\u5185\u5b58\uff0c\u540c\u4e0a <code>extra_jvm_args</code> <code>string[]</code> \u5426 \u989d\u5916 JVM \u53c2\u6570\uff0c\u5982 <code>[\"-XX:+UseG1GC\", \"-XX:MaxGCPauseMillis=50\"]</code> <code>extra_server_args</code> <code>string[]</code> \u5426 \u989d\u5916\u670d\u52a1\u5668\u542f\u52a8\u53c2\u6570\uff0c\u5982 <code>[\"--nogui\"]</code>\uff08\u9002\u7528\u4e8e\u975e\u4ea4\u4e92\u73af\u5883\uff09"},{"location":"guide/configuration.html#_3","title":"\u5404\u5b57\u6bb5\u7528\u6cd5\u793a\u4f8b","text":"<p>\u6307\u5b9a\u670d\u52a1\u5668\u4e13\u7528 Java\uff1a</p> <pre><code>{\n  \"java_path\": \"C:\\\\Program Files\\\\GraalVM\\\\jdk-21.0.2\\\\bin\\\\java.exe\"\n}\n</code></pre> <p>\u7cbe\u7ec6\u5185\u5b58\u63a7\u5236\uff1a</p> <pre><code>{\n  \"min_mem\": \"1G\",\n  \"max_mem\": \"4G\"\n}\n</code></pre> <p>JVM \u8c03\u4f18\u53c2\u6570\uff1a</p> <pre><code>{\n  \"extra_jvm_args\": [\n    \"-XX:+UseZGC\",\n    \"-XX:ZAllocationSpikeTolerance=2.0\",\n    \"-Dfile.encoding=UTF-8\"\n  ]\n}\n</code></pre> <p>\u65e0 GUI \u6a21\u5f0f\uff08\u9002\u5408\u540e\u53f0\u8fd0\u884c\uff09\uff1a</p> <pre><code>{\n  \"extra_server_args\": [\"--nogui\"]\n}\n</code></pre>"},{"location":"guide/configuration.html#java","title":"Java \u7248\u672c\u517c\u5bb9\u8868","text":"MC \u7248\u672c \u6700\u4f4e Java \u63a8\u8350 Java \u8bf4\u660e \u2264 1.12.2 8 8 \u8bb8\u591a\u8001\u724c Mod \u5f3a\u5236\u8981\u6c42 Java 8 1.13 \u2013 1.16.5 8 11 Java 11 \u6027\u80fd\u66f4\u597d 1.17 \u2013 1.17.1 16 17 Java 8 \u4e0d\u518d\u517c\u5bb9 1.18 \u2013 1.20.4 17 17 \u2265 1.20.5 21 21 \u5b98\u65b9\u5f3a\u5236\u7248\u672c \u2265 1.25 25 25 \u6700\u65b0\u5feb\u7167\u7248 <p>MSTL \u5728\u542f\u52a8\u670d\u52a1\u5668\u524d\u4f1a\u81ea\u52a8\u6821\u9a8c\u7248\u672c\uff0c\u4e0d\u517c\u5bb9\u65f6\u63d0\u793a\u5e76\u63d0\u4f9b JDK \u81ea\u52a8\u4e0b\u8f7d\uff08\u652f\u6301 17 / 21 / 25\uff09\u3002</p>"},{"location":"guide/quickstart.html","title":"\u5feb\u901f\u5f00\u59cb","text":""},{"location":"guide/quickstart.html#_2","title":"\u524d\u63d0\u6761\u4ef6","text":"<ul> <li>Python 3.10 \u6216\u66f4\u9ad8\u7248\u672c</li> <li>Git\uff08\u53ef\u9009\uff0c\u4f46\u63a8\u8350\u7528\u4e8e\u514b\u9686\u4ed3\u5e93\u548c\u540e\u7eed\u66f4\u65b0\uff09</li> <li>Java\uff08\u53ef\u9009 \u2014\u2014 \u5982\u679c\u7cfb\u7edf\u6ca1\u6709 Java\uff0cMSTL \u4f1a\u81ea\u52a8\u4e0b\u8f7d JDK 21\uff09</li> </ul>"},{"location":"guide/quickstart.html#_3","title":"\u4e0b\u8f7d","text":"\u901a\u8fc7 Git \u514b\u9686\uff08\u63a8\u8350\uff09\u4e0b\u8f7d ZIP \u538b\u7f29\u5305 <pre><code>git clone https://github.com/yzsyzdy/mc-server-launcher.git\ncd mc-server-launcher\n</code></pre> <p>\u524d\u5f80 GitHub Releases \u4e0b\u8f7d\u6700\u65b0\u7248\u672c\u7684\u6e90\u7801\u538b\u7f29\u5305\uff0c\u89e3\u538b\u540e\u8fdb\u5165\u76ee\u5f55\u3002</p>"},{"location":"guide/quickstart.html#_4","title":"\u9996\u6b21\u542f\u52a8","text":"<pre><code>python start.py\n</code></pre> <p>\u9996\u6b21\u8fd0\u884c\u4f1a\u81ea\u52a8\u6267\u884c\u4ee5\u4e0b\u64cd\u4f5c\uff1a</p> <ol> <li>\u68c0\u6d4b\u7ec8\u7aef\u7f16\u7801\uff08\u652f\u6301 UTF-8\uff09</li> <li>\u52a0\u8f7d\u6216\u521b\u5efa <code>config.json</code>\uff08\u5168\u5c40\u914d\u7f6e\uff09</li> <li>\u521b\u5efa <code>servers/</code> \u76ee\u5f55\uff08\u5b58\u653e\u6240\u6709\u670d\u52a1\u5668\u5b9e\u4f8b\uff09</li> <li>\u626b\u63cf\u7cfb\u7edf Java \u5b89\u88c5</li> <li>\u8fdb\u5165\u4e3b\u83dc\u5355</li> </ol> <p>\u5982\u679c\u5f53\u524d\u76ee\u5f55\u4e0b\u6ca1\u6709\u670d\u52a1\u5668\uff0c\u4f60\u4f1a\u770b\u5230\uff1a</p> <pre><code>[1] \u5bfc\u5165\u5df2\u6709\u670d\u52a1\u5668\n[2] \u4e0b\u8f7d\u65b0\u7684\u670d\u52a1\u7aef\n[0] \u9000\u51fa\n</code></pre>"},{"location":"guide/quickstart.html#_5","title":"\u521b\u5efa\u7b2c\u4e00\u4e2a\u670d\u52a1\u5668","text":""},{"location":"guide/quickstart.html#a","title":"\u65b9\u6848 A\uff1a\u4e0b\u8f7d\u65b0\u670d\u52a1\u7aef","text":"<p>\u5728\u4e3b\u83dc\u5355\u8f93\u5165 <code>2</code>\uff0c\u8fdb\u5165\u670d\u52a1\u7aef\u4e0b\u8f7d\u5411\u5bfc\uff1a</p> <ol> <li>\u9009\u62e9\u670d\u52a1\u7aef\u7c7b\u578b\uff08Paper\u3001Purpur\u3001Fabric\u3001Forge\u2026\u2026\uff09</li> <li>\u9009\u62e9 MC \u7248\u672c\uff08\u5982 <code>1.21.1</code>\uff09</li> <li>\u7b49\u5f85\u4e0b\u8f7d\u5b8c\u6210</li> <li>\u542f\u52a8\u5668\u81ea\u52a8\u751f\u6210 <code>.server.json</code> \u914d\u7f6e\u6587\u4ef6</li> <li>\u8fd4\u56de\u4e3b\u83dc\u5355\u5373\u53ef\u770b\u5230\u65b0\u670d\u52a1\u5668</li> </ol>"},{"location":"guide/quickstart.html#b","title":"\u65b9\u6848 B\uff1a\u5bfc\u5165\u5df2\u6709\u670d\u52a1\u5668","text":"<p>\u5982\u679c\u4f60\u624b\u4e0a\u5df2\u7ecf\u6709\u4e00\u4e2a Minecraft \u670d\u52a1\u7aef\u6587\u4ef6\u5939\u6216\u538b\u7f29\u5305\uff1a</p> <ol> <li>\u4e3b\u83dc\u5355\u8f93\u5165 <code>1</code></li> <li>\u9009\u62e9\u5bfc\u5165\u65b9\u5f0f\uff1a</li> <li>\u5bfc\u5165\u538b\u7f29\u5305\uff1a\u9009\u62e9 <code>.zip</code> \u6587\u4ef6\uff0cMSTL \u81ea\u52a8\u89e3\u538b\u5e76\u8bc6\u522b\u6838\u5fc3 jar</li> <li>\u5bfc\u5165\u76ee\u5f55\uff1a\u6307\u5b9a\u5df2\u6709\u670d\u52a1\u5668\u76ee\u5f55\u8def\u5f84</li> </ol>"},{"location":"guide/quickstart.html#_6","title":"\u542f\u52a8\u670d\u52a1\u5668","text":"<ol> <li>\u5728\u4e3b\u83dc\u5355\u9009\u4e2d\u4f60\u7684\u670d\u52a1\u5668\uff08\u8f93\u5165\u7f16\u53f7\uff09</li> <li>MSTL \u4f1a\u81ea\u52a8\u68c0\u67e5 Java \u7248\u672c\u517c\u5bb9\u6027</li> <li>\u5982\u679c Java \u7248\u672c\u4e0d\u5339\u914d\uff0c\u4f1a\u663e\u793a\u8b66\u544a\u5e76\u8be2\u95ee\u662f\u5426\u81ea\u52a8\u4e0b\u8f7d</li> <li>\u670d\u52a1\u5668\u542f\u52a8\u540e\uff0c\u4f60\u53ef\u4ee5\u5728\u7ec8\u7aef\u76f4\u63a5\u8f93\u5165\u6307\u4ee4\uff08<code>stop</code>\u3001<code>say hello</code>\u3001<code>whitelist add player1</code> \u7b49\uff09</li> </ol> <p>\u9000\u51fa\u670d\u52a1\u5668</p> <p>\u8f93\u5165 <code>stop</code> \u505c\u6b62\u670d\u52a1\u5668\u3002\u5982\u679c EULA \u5c1a\u672a\u63a5\u53d7\uff0cMSTL \u4f1a\u81ea\u52a8\u68c0\u6d4b\u5e76\u8be2\u95ee\u4f60\u662f\u5426\u63a5\u53d7\uff0c\u786e\u8ba4\u540e\u81ea\u52a8\u91cd\u542f\u3002</p>"},{"location":"guide/server-management.html","title":"\u670d\u52a1\u5668\u7ba1\u7406","text":"<p>MSTL \u91c7\u7528\u6bcf\u4e2a\u670d\u52a1\u5668\u72ec\u7acb\u76ee\u5f55\u7684\u8bbe\u8ba1\uff0c\u5404\u81ea\u62e5\u6709\u5b8c\u6574\u7684\u914d\u7f6e\u3001\u6838\u5fc3 jar \u548c\u6570\u636e\u6587\u4ef6\uff0c\u4e92\u4e0d\u5e72\u6270\u3002</p>"},{"location":"guide/server-management.html#_2","title":"\u76ee\u5f55\u7ed3\u6784","text":"<pre><code>servers/\n\u251c\u2500\u2500 \u751f\u5b58\u670d1/\n\u2502   \u251c\u2500\u2500 .server.json          # \u670d\u52a1\u5668\u914d\u7f6e\n\u2502   \u251c\u2500\u2500 paper-1.21.1.jar      # \u670d\u52a1\u7aef\u6838\u5fc3\n\u2502   \u251c\u2500\u2500 eula.txt\n\u2502   \u251c\u2500\u2500 server.properties\n\u2502   \u251c\u2500\u2500 world/                # \u4e16\u754c\u6570\u636e\n\u2502   \u251c\u2500\u2500 plugins/              # \u63d2\u4ef6\n\u2502   \u2514\u2500\u2500 mods/                 # \u6a21\u7ec4\n\u2514\u2500\u2500 \u521b\u9020\u670d2/\n    \u251c\u2500\u2500 .server.json\n    \u251c\u2500\u2500 fabric-server-launch.jar\n    \u2514\u2500\u2500 ...\n</code></pre>"},{"location":"guide/server-management.html#_3","title":"\u670d\u52a1\u5668\u914d\u7f6e","text":"<p>\u6bcf\u4e2a\u670d\u52a1\u5668\u5b9e\u4f8b\u7684\u6838\u5fc3\u914d\u7f6e\u5b58\u50a8\u5728 <code>.server.json</code> \u4e2d\uff1a</p> <pre><code>{\n  \"name\": \"\u751f\u5b58\u670d1\",\n  \"mc_version\": \"1.21.1\",\n  \"jar\": \"leaves.jar\",\n  \"java_path\": null,\n  \"min_mem\": \"2G\",\n  \"max_mem\": \"8G\",\n  \"extra_jvm_args\": [],\n  \"extra_server_args\": []\n}\n</code></pre> <p>\u8be6\u7ec6\u5b57\u6bb5\u8bf4\u660e\u8bf7\u524d\u5f80 \u914d\u7f6e\u8bf4\u660e\u3002</p>"},{"location":"guide/server-management.html#_4","title":"\u542f\u52a8\u4e0e\u505c\u6b62","text":""},{"location":"guide/server-management.html#_5","title":"\u542f\u52a8\u670d\u52a1\u5668","text":"<p>\u5728\u4e3b\u83dc\u5355\u9009\u4e2d\u76ee\u6807\u670d\u52a1\u5668\u540e\uff0cMSTL \u4f1a\u4f9d\u6b21\u6267\u884c\uff1a</p> <ol> <li>Java \u89e3\u6790\uff1a\u5148\u67e5\u7f13\u5b58 \u2192 \u626b\u63cf\u7cfb\u7edf \u2192 \u5982\u65e0\u53ef\u81ea\u52a8\u4e0b\u8f7d</li> <li>\u7248\u672c\u6821\u9a8c\uff1a\u68c0\u67e5 MC \u7248\u672c\u4e0e Java \u7248\u672c\u662f\u5426\u517c\u5bb9</li> <li>\u8fdb\u7a0b\u542f\u52a8\uff1a\u4ee5\u5b50\u8fdb\u7a0b\u5f62\u5f0f\u542f\u52a8\u670d\u52a1\u5668\uff0c\u5b9e\u65f6\u6355\u83b7 stdout</li> <li>\u4ea4\u4e92\u63a7\u5236\u53f0\uff1a\u81ea\u52a8\u8fdb\u5165\u63a7\u5236\u53f0\u6a21\u5f0f\uff0c\u53ef\u76f4\u63a5\u8f93\u5165\u6307\u4ee4</li> </ol>"},{"location":"guide/server-management.html#_6","title":"\u505c\u6b62\u670d\u52a1\u5668","text":"<p>\u5728\u63a7\u5236\u53f0\u8f93\u5165 <code>stop</code>\uff0cMSTL \u4f1a\u5c06\u6307\u4ee4\u4f20\u9012\u7ed9\u670d\u52a1\u5668\u8fdb\u7a0b\uff0c\u7b49\u5f85\u5176\u81ea\u7136\u9000\u51fa\u3002</p> <p>\u5982\u679c\u9700\u8981\u5f3a\u5236\u7ec8\u6b62\uff0c\u6309 <code>Ctrl+C</code> \u4e24\u6b21\u3002</p>"},{"location":"guide/server-management.html#eula","title":"EULA \u81ea\u52a8\u5904\u7406","text":"<p>\u670d\u52a1\u5668\u9996\u6b21\u542f\u52a8\u9000\u51fa\u540e\uff0cMSTL \u4f1a\u68c0\u6d4b <code>eula.txt</code>\uff1a</p> <ul> <li>\u5982\u679c <code>eula=false</code>\uff0c\u81ea\u52a8\u8be2\u95ee\u662f\u5426\u63a5\u53d7</li> <li>\u786e\u8ba4\u540e\u5199\u5165 <code>eula=true</code>\uff0c\u81ea\u52a8\u91cd\u542f\u670d\u52a1\u5668</li> </ul>"},{"location":"guide/server-management.html#_7","title":"\u5bfc\u5165\u5df2\u6709\u670d\u52a1\u5668","text":""},{"location":"guide/server-management.html#_8","title":"\u4ece\u538b\u7f29\u5305\u5bfc\u5165","text":"<ol> <li>\u4e3b\u83dc\u5355\u9009\u62e9\u300c\u5bfc\u5165\u300d</li> <li>\u9009\u62e9\u300c\u5bfc\u5165\u538b\u7f29\u5305\u300d</li> <li>\u6d4f\u89c8\u5e76\u9009\u4e2d <code>.zip</code> \u6587\u4ef6</li> <li>MSTL \u81ea\u52a8\u89e3\u538b\u5230 <code>servers/&lt;\u6587\u4ef6\u5939\u540d&gt;/</code></li> <li>\u81ea\u52a8\u626b\u63cf\u5e76\u8bc6\u522b\u6838\u5fc3 jar\uff08\u5982\u627e\u5230\u591a\u4e2a\uff0c\u4f1a\u8ba9\u4f60\u9009\u62e9\uff09</li> <li>\u81ea\u52a8\u751f\u6210 <code>.server.json</code></li> </ol>"},{"location":"guide/server-management.html#_9","title":"\u4ece\u76ee\u5f55\u5bfc\u5165","text":"<p>\u76f4\u63a5\u6307\u5b9a\u4e00\u4e2a\u73b0\u6709\u670d\u52a1\u5668\u76ee\u5f55\uff0cMSTL \u4f1a\u5c06\u5176\u590d\u5236\u5230 <code>servers/</code> \u4e0b\u5e76\u81ea\u52a8\u914d\u7f6e\u3002</p>"},{"location":"guide/server-management.html#_10","title":"\u591a\u670d\u52a1\u5668\u5e76\u884c","text":"<p>\u6bcf\u4e2a\u670d\u52a1\u5668\u5b9e\u4f8b\u662f\u72ec\u7acb\u7684\u5b50\u8fdb\u7a0b\uff0c\u4e92\u4e0d\u4f9d\u8d56\u3002\u4f60\u53ef\u4ee5\uff1a</p> <ul> <li>\u542f\u52a8\u4e00\u4e2a\u670d\u52a1\u5668\u540e\u56de\u5230\u4e3b\u83dc\u5355\u542f\u52a8\u53e6\u4e00\u4e2a</li> <li>\u5206\u522b\u7ba1\u7406\u5404\u81ea\u7684\u63d2\u4ef6\u3001\u6a21\u7ec4\u548c\u914d\u7f6e</li> <li>\u5b9e\u4f8b\u4e4b\u95f4\u5b8c\u5168\u9694\u79bb\uff0c\u4e0d\u4f1a\u4ea7\u751f\u51b2\u7a81</li> </ul>"},{"location":"en/index.html","title":"MSTLMinecraft Terminal Server Launcher","text":"\ud83d\udc19 v1.1.0 \u00b7 GPLv3 \u00b7 zero dependencies <p>Lightweight \u00b7 Zero-dependency \u00b7 Cross-platformMinecraft server manager</p> MSTL \u2014 Server Console $ python start.py # First run auto-creates config.json and servers/ Select a server to start:   [1] survival-1.21  MC 1.21.1 | paper.jar | 2G/8G   [2] creative-1.20  MC 1.20.4 | vanilla.jar | 4G/16G   [0] Exit &gt; 1 Java Detected Adoptium JDK 21.0.2 Check MC 1.21.1 \u2192 Java 21 \u2713 Compatible Launch Memory min 2G / max 8G Ready Starting Minecraft server on *:25565 Done Done (2.1s)! Type \"help\" for help &gt;"},{"location":"en/index.html#at-a-glance","title":"\ud83d\udcca At a Glance","text":"30+Server types 3Plugin markets 2Mod repos 0Dependencies 3Languages"},{"location":"en/index.html#core-features","title":"\ud83d\udda5 Core Features","text":"\ud83d\udccb Multi-instance Management <p>Each server in its own isolated directory. Supports 30+ server types: Paper, Purpur, Fabric, Forge, NeoForge, Velocity, and more.</p> \u2615 Automatic Java Management <p>Scans environment variables and install paths. Auto-downloads GraalVM JDK (17 / 21 / 25) when missing or incompatible.</p> \u2b07\ufe0f Multithreaded Download <p>16 concurrent threads with chunked Range requests. Automatic fallback to single-thread when unsupported.</p> \ud83e\udde9 Plugin Management <p>Search across SpigotMC (Spiget), Modrinth, and Hangar in parallel. Sorted by downloads, one-click install.</p> \ud83d\udce6 Mod Management <p>Modrinth and CurseForge dual-source search. Auto-filters by MC version and loader, with smart fallback broadening.</p> \ud83d\ude87 Tunnel (OpenFrp) <p>Integrated OpenFrp support. Auto-downloads frpc for your architecture, tunnels follow server lifecycle.</p> \ud83d\udcbb Interactive Console <p>Send any command (stop, say, whitelist, op) directly from the terminal. Real-time log output.</p> \ud83c\udf10 Internationalization <p>Built-in English, Chinese, Russian. Add a language by dropping a JSON file in the locales/ directory.</p>"},{"location":"en/index.html#quick-start","title":"\ud83d\ude80 Quick Start","text":"<pre><code>git clone https://github.com/yzsyzdy/mc-server-launcher.git\ncd mc-server-launcher\npython start.py\n</code></pre> <p>Prerequisites</p> <ul> <li>Python 3.10+ (stdlib only, zero third-party dependencies)</li> <li>Java (optional \u2014 the launcher can download JDK 21 automatically)</li> </ul>"},{"location":"en/index.html#roadmap","title":"\ud83d\uddfa Roadmap","text":"<ul> <li>\u2705 Multi-server instance management</li> <li>\u2705 Automatic Java detection &amp; download</li> <li>\u2705 Plugin search &amp; install (SpigotMC / Modrinth / Hangar)</li> <li>\u2705 Mod search &amp; install (Modrinth / CurseForge)</li> <li>\u2705 Multithreaded download engine</li> <li>\u2705 OpenFrp tunnel integration</li> <li>\u2705 Internationalization (\u4e2d\u6587 / English / \u0420\u0443\u0441\u0441\u043a\u0438\u0439)</li> <li>\u2b55 GUI</li> <li>\u2b55 Remote web dashboard</li> </ul>"},{"location":"en/index.html#license","title":"\u2696 License","text":"<p>GNU General Public License v3.0</p>"},{"location":"en/faq.html","title":"Frequently Asked Questions","text":""},{"location":"en/faq.html#curseforge-search-not-working","title":"CurseForge search not working?","text":"<p>Set <code>curseforge_api_key</code> in <code>config.json</code>. Get a free API key at CurseForge Console.</p> <pre><code>{\n  \"curseforge_api_key\": \"your-api-key\"\n}\n</code></pre>"},{"location":"en/faq.html#plugin-download-from-spigotmc-fails","title":"Plugin download from SpigotMC fails?","text":"<p>Some plugins are hosted externally (e.g., on GitHub). MSTL detects this and resolves the real jar via the GitHub API.</p> <p>If it still fails:</p> <ol> <li>Check your internet connection</li> <li>Open the provided download URL in your browser</li> <li>Download manually and use \"Import local jar\"</li> </ol>"},{"location":"en/faq.html#cant-find-chinese-named-mods","title":"Can't find Chinese-named mods?","text":"<p>Modrinth's search index depends on mod descriptions. Most mods use English names. Search with English keywords for best results.</p>"},{"location":"en/faq.html#slow-downloads","title":"Slow downloads?","text":"<p>MSTL uses 16 concurrent threads by default. Call <code>set_download_threads(n)</code> to adjust.</p> <p>Falls back to single-threaded download when the server doesn't support Range requests.</p>"},{"location":"en/faq.html#java-not-detected","title":"Java not detected?","text":"<p>MSTL searches in this order:</p> <ol> <li><code>java_path</code> in <code>config.json</code></li> <li><code>JAVA_HOME</code> environment variable</li> <li><code>java</code> command in <code>PATH</code></li> <li>Standard install paths (e.g. <code>Program Files\\Java\\</code> on Windows)</li> </ol> <p>If nothing is found, MSTL offers to download GraalVM JDK automatically.</p>"},{"location":"en/faq.html#how-to-change-server-memory","title":"How to change server memory?","text":"<p>Edit the server's <code>.server.json</code>:</p> <pre><code>{\n  \"min_mem\": \"2G\",\n  \"max_mem\": \"4G\"\n}\n</code></pre> <p>Use <code>G</code> for GB or <code>M</code> for MB. Restart the server to apply.</p>"},{"location":"en/faq.html#can-i-run-multiple-servers-at-once","title":"Can I run multiple servers at once?","text":"<p>Yes. Each server is an independent child process. Switch between them freely from the main menu.</p>"},{"location":"en/faq.html#how-to-back-up-a-server","title":"How to back up a server?","text":"<p>All server data is in <code>servers/&lt;name&gt;/</code>. Compress the directory to back up. Use \"Import archive\" to restore.</p>"},{"location":"en/faq.html#frpc-download-fails","title":"frpc download fails?","text":"<p>MSTL downloads frpc from OpenFrp mirrors. If it fails:</p> <ol> <li>Check if you can reach the OpenFrp mirror</li> <li>Download frpc manually from the OpenFrp website</li> <li>Place the binary in the <code>openfrp/</code> directory</li> </ol>"},{"location":"en/faq.html#found-a-bug-or-have-a-feature-request","title":"Found a bug or have a feature request?","text":"<p>Open an issue at GitHub Issues. Please include:</p> <ul> <li>OS version</li> <li>Python version (<code>python --version</code>)</li> <li>Error logs (if any)</li> <li>Steps to reproduce</li> </ul>"},{"location":"en/advanced/index.html","title":"Advanced","text":"<p>Deep dive into MSTL's internal design.</p> \ud83c\udfd7\ufe0f Architecture <p>Module breakdown, data flow, and runtime lifecycle.</p> \ud83d\udd27 Building from Source <p>Development setup and packaging as a standalone executable.</p>"},{"location":"en/advanced/architecture.html","title":"Architecture","text":""},{"location":"en/advanced/architecture.html#design-principles","title":"Design Principles","text":"<ul> <li>Zero external dependencies: Python stdlib only, no <code>pip install</code> needed</li> <li>Least surprise: Intuitive organization, sensible defaults</li> <li>Interface over implementation: Plugin sources, mod sources, Java detection all follow unified abstractions</li> </ul>"},{"location":"en/advanced/architecture.html#module-structure","title":"Module Structure","text":"<pre><code>mc-server-launcher/\n\u2502\n\u251c\u2500\u2500 start.py               # Entry point\n\u251c\u2500\u2500 config.py              # Global config (config.json) read/write\n\u251c\u2500\u2500 clear.py               # Cross-platform terminal clear\n\u2502\n\u251c\u2500\u2500 server_manager.py      # Server instance directory management\n\u251c\u2500\u2500 server_launcher.py     # Server child process management\n\u251c\u2500\u2500 download_msl.py        # MSL mirror interaction + multithreaded download engine\n\u2502\n\u251c\u2500\u2500 java_tools.py          # Java detection, JDK download, version compatibility\n\u2502\n\u251c\u2500\u2500 plugin_sources.py      # Plugin search &amp; download abstraction layer\n\u251c\u2500\u2500 mod_sources.py         # Mod search &amp; download abstraction layer\n\u2502\n\u251c\u2500\u2500 menu.py                # Interactive menu system\n\u251c\u2500\u2500 i18n.py                # Internationalization\n\u2502\n\u251c\u2500\u2500 openfrp/               # OpenFrp tunnel module\n\u2502   \u2514\u2500\u2500 ...\n\u2502\n\u251c\u2500\u2500 locales/               # Language files\n\u2502   \u251c\u2500\u2500 zh.json\n\u2502   \u251c\u2500\u2500 en.json\n\u2502   \u2514\u2500\u2500 ru.json\n\u2502\n\u2514\u2500\u2500 website/               # Project website (standalone HTML)\n    \u251c\u2500\u2500 index.html\n    \u2514\u2500\u2500 lang.js\n</code></pre>"},{"location":"en/advanced/architecture.html#module-responsibilities","title":"Module Responsibilities","text":""},{"location":"en/advanced/architecture.html#startup-flow-startpy","title":"Startup Flow (start.py)","text":"<pre><code>start.py\n  \u2502\n  \u251c\u2500 Clear screen\n  \u251c\u2500 Load config.json (config.py)\n  \u251c\u2500 Load i18n (i18n.py)\n  \u251c\u2500 Create servers/ directory\n  \u2502\n  \u251c\u2500 First run \u2192 Import/Download wizard\n  \u2502\n  \u2514\u2500 Servers exist \u2192 Show list\n       \u2502\n       \u25bc Select server\n       \u2502\n       \u251c\u2500 Java resolution (java_tools.py)\n       \u2502   \u251c\u2500 Check cache\n       \u2502   \u251c\u2500 Scan system paths\n       \u2502   \u251c\u2500 Version compatibility check\n       \u2502   \u2514\u2500 If missing \u2192 auto-download GraalVM JDK\n       \u2502\n       \u251c\u2500 Launch child process (server_launcher.py)\n       \u2502   \u251c\u2500 Build JVM command\n       \u2502   \u251c\u2500 Create subprocess\n       \u2502   \u2514\u2500 Capture stdout\n       \u2502\n       \u2514\u2500 Interactive console\n           \u251c\u2500 Commands \u2192 server stdin\n           \u2514\u2500 Logs \u2190 server stdout\n</code></pre>"},{"location":"en/advanced/architecture.html#multithreaded-download-engine-download_mslpy","title":"Multithreaded Download Engine (download_msl.py)","text":"<pre><code>Request URL\n  \u2502\n  \u251c\u2500 HEAD request to check Range support\n  \u2502   \u251c\u2500 Supported \u2192 Split into 16 chunks, download concurrently\n  \u2502   \u2502                Write to temp files, merge on completion\n  \u2502   \u2514\u2500 Not supported \u2192 Single-threaded download\n  \u2502\n  \u2514\u2500 Progress reporting (bytes / total / speed)\n</code></pre>"},{"location":"en/advanced/architecture.html#pluginmod-search-architecture","title":"Plugin/Mod Search Architecture","text":"<pre><code>Unified search interface\n  \u2502\n  \u251c\u2500 Parallel queries across sources\n  \u2502   \u251c\u2500 SpigotMC (Spiget)\n  \u2502   \u251c\u2500 Modrinth\n  \u2502   \u251c\u2500 Hangar\n  \u2502   \u2514\u2500 CurseForge\n  \u2502\n  \u251c\u2500 Merge results\n  \u251c\u2500 Sort by download count (descending)\n  \u2514\u2500 Display to user\n</code></pre>"},{"location":"en/advanced/build.html","title":"Building from Source","text":"<p>MSTL is pure Python \u2014 you can run it directly. If you want a standalone executable, here's how.</p>"},{"location":"en/advanced/build.html#local-development","title":"Local Development","text":""},{"location":"en/advanced/build.html#clone","title":"Clone","text":"<pre><code>git clone https://github.com/yzsyzdy/mc-server-launcher.git\ncd mc-server-launcher\n</code></pre>"},{"location":"en/advanced/build.html#run","title":"Run","text":"<pre><code>python start.py\n</code></pre> <p>No virtual environment needed. No packages to install.</p>"},{"location":"en/advanced/build.html#packaging-as-executable","title":"Packaging as Executable","text":""},{"location":"en/advanced/build.html#using-nuitka-recommended","title":"Using Nuitka (recommended)","text":"<p>Nuitka compiles Python to a standalone binary with faster startup than PyInstaller.</p> <pre><code>pip install nuitka\npython -m nuitka --standalone --onefile start.py\n</code></pre> <p>Output: <code>start.exe</code> (Windows) or <code>start</code> (Linux).</p>"},{"location":"en/advanced/build.html#using-pyinstaller","title":"Using PyInstaller","text":"<pre><code>pip install pyinstaller\npyinstaller --onefile start.py\n</code></pre> <p>Output: <code>dist/start.exe</code>.</p>"},{"location":"en/advanced/build.html#contributing-translations","title":"Contributing Translations","text":"<p>To add a new language:</p> <ol> <li>Create <code>locales/{code}.json</code></li> <li>Translate all keys based on <code>zh.json</code></li> <li>Add the language display name in <code>i18n.py</code>'s <code>lang_names</code> dict</li> </ol> <p>Current languages:</p> Code Language Maintainer <code>zh</code> Chinese yzsyzdy <code>en</code> English yzsyzdy <code>ru</code> Russian \u2014"},{"location":"en/advanced/build.html#contribution-guide","title":"Contribution Guide","text":"<ol> <li>Fork the project</li> <li>Create a feature branch: <code>git checkout -b feature/my-feature</code></li> <li>Commit: <code>git commit -am 'Add some feature'</code></li> <li>Push: <code>git push origin feature/my-feature</code></li> <li>Open a Pull Request</li> </ol> <p>Guidelines:</p> <ul> <li>Keep the zero-dependency principle</li> <li>Add menu items and i18n translations for new features</li> <li>Test on both Windows and Linux</li> </ul>"},{"location":"en/features/index.html","title":"Features","text":"<p>Detailed breakdown of MSTL's core features.</p> \ud83e\udde9 Plugin Management <p>Multi-source search, one-click download, enable/disable. Supports SpigotMC, Modrinth, Hangar.</p> \ud83d\udce6 Mod Management <p>Modrinth and CurseForge dual-source search. Auto-filters by MC version and loader.</p> \ud83d\ude87 Tunnel (OpenFrp) <p>Integrated OpenFrp support. Auto-downloads frpc, tunnels start and stop with your server.</p>"},{"location":"en/features/mod-management.html","title":"Mod Management","text":"<p>MSTL searches and downloads mods from multiple platforms, auto-matching your server's MC version and mod loader.</p>"},{"location":"en/features/mod-management.html#supported-sources","title":"Supported Sources","text":"Source API Key Notes Modrinth Not required Largest Fabric/Quilt/Forge mod platform CurseForge Required (optional) Traditional mod platform"},{"location":"en/features/mod-management.html#configuring-curseforge-api-key","title":"Configuring CurseForge API Key","text":"<ol> <li>Go to CurseForge Console and register for an API key</li> <li>Add it to <code>config.json</code>:</li> </ol> <pre><code>{\n  \"curseforge_api_key\": \"your-api-key-here\"\n}\n</code></pre>"},{"location":"en/features/mod-management.html#searching","title":"Searching","text":"<p>From the main menu, select a server \u2192 Mod management \u2192 enter keywords.</p> <p>MSTL will:</p> <ol> <li>Read the server's MC version and mod loader (e.g. Fabric 1.21.1)</li> <li>Search Modrinth (and CurseForge if configured)</li> <li>Auto-filter matching versions and loaders</li> <li>Broaden the search scope if too few results are found</li> </ol> <pre><code>Searching \"jei\" (Fabric \u00b7 1.21.1):\n\n[Modrinth] 12 results:\n 1. JEI (Just Enough Items) \u2014 1.21.1-fabric \u2014 12,345,678 downloads\n 2. JEI Integration \u2014 1.21.1-fabric \u2014 234,567 downloads\n...\n</code></pre>"},{"location":"en/features/mod-management.html#download","title":"Download","text":"<p>Select a result. MSTL downloads the matching jar with 16 threads and places it in <code>mods/</code>.</p>"},{"location":"en/features/mod-management.html#local-import-toggle","title":"Local Import &amp; Toggle","text":"<p>Same as plugin management:</p> <ul> <li>Import: select a <code>.jar</code> file, copied to <code>mods/</code></li> <li>Disable: <code>mods/mod.jar</code> \u2192 <code>mods/mod.jar.disabled</code></li> <li>Enable: reverse</li> </ul>"},{"location":"en/features/plugin-management.html","title":"Plugin Management","text":"<p>MSTL integrates multi-source plugin search and download.</p>"},{"location":"en/features/plugin-management.html#supported-sources","title":"Supported Sources","text":"Source API Key Required Notes SpigotMC Spiget API No Largest Bukkit/Spigot plugin community Modrinth Modrinth API No Supports Fabric/Quilt and Bukkit plugins Hangar Hangar API No PaperMC's official plugin platform"},{"location":"en/features/plugin-management.html#searching","title":"Searching","text":"<p>From the main menu, select a server \u2192 Plugin management \u2192 enter keywords.</p> <p>MSTL searches all three sources in parallel and sorts results by download count:</p> <pre><code>[SpigotMC] 8 results:\n 1. EssentialsX (2,341,592 downloads) \u2014 v2.21.0\n 2. LuckPerms (1,892,333 downloads) \u2014 v5.4.151\n...\n[Modrinth] 5 results:\n 7. Spark (890,234 downloads) \u2014 v1.10.109\n...\n</code></pre>"},{"location":"en/features/plugin-management.html#tips","title":"Tips","text":"<ul> <li>Use precise keywords (e.g. <code>EssentialsX</code> rather than <code>ess</code>)</li> <li>Externally hosted plugins (e.g. on GitHub) are auto-resolved via the GitHub API</li> </ul>"},{"location":"en/features/plugin-management.html#download-install","title":"Download &amp; Install","text":"<p>Select a result number. MSTL will:</p> <ol> <li>Resolve the latest jar download URL</li> <li>Download with 16 concurrent threads</li> <li>Place the jar in the server's <code>plugins/</code> directory</li> <li>Prompt to restart the server</li> </ol>"},{"location":"en/features/plugin-management.html#enable-disable","title":"Enable &amp; Disable","text":"<p>MSTL controls plugin state by renaming jar files:</p> <ul> <li>Disable: <code>plugins/plugin.jar</code> \u2192 <code>plugins/plugin.jar.disabled</code></li> <li>Enable: <code>plugins/plugin.jar.disabled</code> \u2192 <code>plugins/plugin.jar</code></li> </ul> <p>No files are deleted \u2014 you can always re-enable later.</p>"},{"location":"en/features/plugin-management.html#local-import","title":"Local Import","text":"<ol> <li>Select \"Import local jar\" in plugin management</li> <li>Browse and select a <code>.jar</code> file</li> <li>The file is copied to <code>plugins/</code></li> </ol>"},{"location":"en/features/tunnel.html","title":"Tunnel (OpenFrp)","text":"<p>MSTL integrates OpenFrp tunnel support for exposing your Minecraft server to the public internet.</p>"},{"location":"en/features/tunnel.html#prerequisites","title":"Prerequisites","text":"<ol> <li>Register at OpenFrp</li> <li>Get your user token from the OpenFrp Console</li> </ol>"},{"location":"en/features/tunnel.html#workflow","title":"Workflow","text":""},{"location":"en/features/tunnel.html#step-1-list-tunnels","title":"Step 1: List Tunnels","text":"<ol> <li>Main menu \u2192 OpenFrp (option 6)</li> <li>Select List tunnels</li> <li>Enter your OpenFrp token</li> <li>MSTL fetches all tunnels under your account</li> </ol> <pre><code>OpenFrp tunnels:\n[1] Survival (Node: Shanghai-1 \u2192 Localhost:25565) \u2014 Running\n[2] Creative (Node: Guangzhou-2 \u2192 Localhost:25566) \u2014 Stopped\n</code></pre>"},{"location":"en/features/tunnel.html#step-2-bind-tunnel-to-server","title":"Step 2: Bind Tunnel to Server","text":"<ol> <li>OpenFrp menu \u2192 Bind tunnel to server</li> <li>Select a tunnel</li> <li>Select the local server instance</li> <li>Once bound, the tunnel starts automatically when the server starts</li> </ol>"},{"location":"en/features/tunnel.html#step-3-start","title":"Step 3: Start","text":"<p>Just start your server normally. MSTL handles everything:</p> <pre><code>Start server process\n  \u2514\u2500 Check if bound to a tunnel\n       \u2514\u2500 Yes \u2192 Check frpc binary\n            \u251c\u2500 Missing \u2192 Auto-download frpc for your architecture\n            \u2514\u2500 Exists \u2192 Start frpc tunnel\n</code></pre>"},{"location":"en/features/tunnel.html#automatic-frpc-management","title":"Automatic frpc Management","text":"<p>MSTL automatically:</p> <ul> <li>Detects system architecture: Windows / Linux, x86_64 / arm64</li> <li>Downloads frpc: from OpenFrp mirrors</li> <li>Starts/stops frpc: follows the server lifecycle</li> </ul> <p>No manual frpc setup required.</p>"},{"location":"en/features/tunnel.html#create-a-new-tunnel","title":"Create a New Tunnel","text":"<ol> <li>OpenFrp menu \u2192 Create tunnel</li> <li>Follow the wizard:</li> <li>Tunnel name</li> <li>Node selection</li> <li>Local port (e.g. <code>25565</code>)</li> <li>Remote port type (TCP)</li> </ol> <p>The new tunnel appears in your list immediately.</p>"},{"location":"en/guide/index.html","title":"User Guide","text":"<p>Guides from installation to daily operation.</p> \ud83d\ude80 Quick Start <p>From zero to your first server: download, launch, configuration.</p> \ud83d\udda5 Server Management <p>Multi-instance management, start/stop, archive import, console operations.</p> \u2699\ufe0f Configuration <p>Global and per-server configuration field reference.</p> <p>Start with Quick Start if you're new to MSTL.</p>"},{"location":"en/guide/configuration.html","title":"Configuration","text":"<p>MSTL has two configuration layers: global and per-server.</p>"},{"location":"en/guide/configuration.html#global-config-configjson","title":"Global Config (config.json)","text":"<p>Located in the project root, auto-created on first run.</p> <pre><code>{\n  \"java_path\": null,\n  \"interactive\": true,\n  \"language\": \"\",\n  \"curseforge_api_key\": \"\"\n}\n</code></pre> Field Type Default Description <code>java_path</code> <code>string \\| null</code> <code>null</code> Explicit Java executable path. <code>null</code> = auto-detect <code>interactive</code> <code>boolean</code> <code>true</code> Enable interactive console mode <code>language</code> <code>string</code> <code>\"\"</code> UI language code (<code>\"zh\"</code> / <code>\"en\"</code> / <code>\"ru\"</code>). Empty = auto-detect system language <code>curseforge_api_key</code> <code>string</code> <code>\"\"</code> CurseForge API key. Required for CurseForge mod search"},{"location":"en/guide/configuration.html#server-config-serverjson","title":"Server Config (.server.json)","text":"<p>Each server instance has its own config at <code>servers/&lt;name&gt;/.server.json</code>.</p> <pre><code>{\n  \"name\": \"survival1\",\n  \"mc_version\": \"1.21.1\",\n  \"jar\": \"leaves.jar\",\n  \"java_path\": null,\n  \"min_mem\": \"2G\",\n  \"max_mem\": \"8G\",\n  \"extra_jvm_args\": [],\n  \"extra_server_args\": []\n}\n</code></pre>"},{"location":"en/guide/configuration.html#field-reference","title":"Field Reference","text":"Field Type Required Description <code>name</code> <code>string</code> Yes Display name <code>mc_version</code> <code>string</code> Yes Minecraft version (e.g. <code>1.21.1</code>) <code>jar</code> <code>string</code> Yes Server core jar filename <code>java_path</code> <code>string \\| null</code> No Server-specific Java path. <code>null</code> = use global <code>min_mem</code> <code>string</code> No Minimum memory (<code>G</code> / <code>M</code> suffix, e.g. <code>2G</code>) <code>max_mem</code> <code>string</code> No Maximum memory <code>extra_jvm_args</code> <code>string[]</code> No Extra JVM arguments <code>extra_server_args</code> <code>string[]</code> No Extra server arguments"},{"location":"en/guide/configuration.html#examples","title":"Examples","text":"<p>Per-server Java:</p> <pre><code>{\n  \"java_path\": \"C:\\\\Program Files\\\\GraalVM\\\\jdk-21.0.2\\\\bin\\\\java.exe\"\n}\n</code></pre> <p>JVM tuning:</p> <pre><code>{\n  \"extra_jvm_args\": [\n    \"-XX:+UseZGC\",\n    \"-XX:ZAllocationSpikeTolerance=2.0\"\n  ]\n}\n</code></pre>"},{"location":"en/guide/configuration.html#java-version-compatibility","title":"Java Version Compatibility","text":"MC Version Min Java Recommended Notes \u2264 1.12.2 8 8 Many legacy mods require Java 8 1.13 \u2013 1.16.5 8 11 Java 11 performs better 1.17 \u2013 1.17.1 16 17 Java 8 no longer supported 1.18 \u2013 1.20.4 17 17 \u2265 1.20.5 21 21 Official requirement \u2265 1.25 25 25 Latest snapshot <p>MSTL auto-checks compatibility and offers JDK download (17/21/25) when needed.</p>"},{"location":"en/guide/quickstart.html","title":"Quick Start","text":""},{"location":"en/guide/quickstart.html#prerequisites","title":"Prerequisites","text":"<ul> <li>Python 3.10 or later</li> <li>Git (optional but recommended for cloning and updates)</li> <li>Java (optional \u2014 MSTL can download JDK 21 automatically)</li> </ul>"},{"location":"en/guide/quickstart.html#download","title":"Download","text":"Clone with Git (recommended)Download ZIP <pre><code>git clone https://github.com/yzsyzdy/mc-server-launcher.git\ncd mc-server-launcher\n</code></pre> <p>Go to GitHub Releases and download the latest source archive. Extract and enter the directory.</p>"},{"location":"en/guide/quickstart.html#first-launch","title":"First Launch","text":"<pre><code>python start.py\n</code></pre> <p>On first run, MSTL will:</p> <ol> <li>Detect terminal encoding (UTF-8 required)</li> <li>Load or create <code>config.json</code></li> <li>Create the <code>servers/</code> directory</li> <li>Scan for installed Java</li> <li>Show the main menu</li> </ol> <p>If no servers exist, you'll see:</p> <pre><code>[1] Import existing server\n[2] Download new server core\n[0] Exit\n</code></pre>"},{"location":"en/guide/quickstart.html#create-your-first-server","title":"Create Your First Server","text":""},{"location":"en/guide/quickstart.html#option-a-download-a-new-server-core","title":"Option A: Download a New Server Core","text":"<p>Press <code>2</code> at the main menu:</p> <ol> <li>Choose server type (Paper, Purpur, Fabric, Forge\u2026)</li> <li>Choose MC version (e.g. <code>1.21.1</code>)</li> <li>Wait for download</li> <li>MSTL auto-generates <code>.server.json</code></li> <li>Return to the main menu \u2014 your new server is listed</li> </ol>"},{"location":"en/guide/quickstart.html#option-b-import-an-existing-server","title":"Option B: Import an Existing Server","text":"<p>If you already have a server folder or archive:</p> <ol> <li>Press <code>1</code> at the main menu</li> <li>Choose import method:</li> <li>Import archive: select a <code>.zip</code> file, auto-extract and detect the core jar</li> <li>Import directory: specify an existing server folder</li> </ol>"},{"location":"en/guide/quickstart.html#start-the-server","title":"Start the Server","text":"<ol> <li>Select your server from the menu (enter the number)</li> <li>MSTL checks Java version compatibility</li> <li>If Java is incompatible, a warning is shown and auto-download is offered</li> <li>Once the server starts, enter commands directly (<code>stop</code>, <code>say hello</code>, <code>whitelist add player1</code>\u2026)</li> </ol> <p>Stopping the server</p> <p>Type <code>stop</code> to gracefully stop. If the EULA hasn't been accepted, MSTL detects it and asks before automatically restarting.</p>"},{"location":"en/guide/server-management.html","title":"Server Management","text":"<p>Each server instance lives in its own directory with complete isolation.</p>"},{"location":"en/guide/server-management.html#directory-structure","title":"Directory Structure","text":"<pre><code>servers/\n\u251c\u2500\u2500 survival1/\n\u2502   \u251c\u2500\u2500 .server.json          # Server config\n\u2502   \u251c\u2500\u2500 paper-1.21.1.jar      # Server core\n\u2502   \u251c\u2500\u2500 eula.txt\n\u2502   \u251c\u2500\u2500 server.properties\n\u2502   \u251c\u2500\u2500 world/                # World data\n\u2502   \u251c\u2500\u2500 plugins/              # Plugins\n\u2502   \u2514\u2500\u2500 mods/                 # Mods\n\u2514\u2500\u2500 creative2/\n    \u251c\u2500\u2500 .server.json\n    \u251c\u2500\u2500 fabric-server-launch.jar\n    \u2514\u2500\u2500 ...\n</code></pre>"},{"location":"en/guide/server-management.html#server-config","title":"Server Config","text":"<p>Each server's core config is stored in <code>.server.json</code>:</p> <pre><code>{\n  \"name\": \"survival1\",\n  \"mc_version\": \"1.21.1\",\n  \"jar\": \"leaves.jar\",\n  \"java_path\": null,\n  \"min_mem\": \"2G\",\n  \"max_mem\": \"8G\",\n  \"extra_jvm_args\": [],\n  \"extra_server_args\": []\n}\n</code></pre> <p>See Configuration for field details.</p>"},{"location":"en/guide/server-management.html#start-stop","title":"Start &amp; Stop","text":""},{"location":"en/guide/server-management.html#starting","title":"Starting","text":"<p>Select a server from the menu. MSTL will:</p> <ol> <li>Java resolution: check cache \u2192 scan system \u2192 auto-download if missing</li> <li>Version validation: verify MC version vs Java compatibility</li> <li>Process launch: start the server as a child process, capture stdout</li> <li>Interactive console: enter commands directly</li> </ol>"},{"location":"en/guide/server-management.html#stopping","title":"Stopping","text":"<p>Type <code>stop</code> in the console. MSTL forwards the command to the server process and waits for graceful shutdown.</p> <p>Press <code>Ctrl+C</code> twice for a forced kill.</p>"},{"location":"en/guide/server-management.html#eula-handling","title":"EULA Handling","text":"<p>After the server first exits, MSTL checks <code>eula.txt</code>:</p> <ul> <li>If <code>eula=false</code>, prompts for acceptance</li> <li>On confirmation, writes <code>eula=true</code> and restarts automatically</li> </ul>"},{"location":"en/guide/server-management.html#import-existing-servers","title":"Import Existing Servers","text":""},{"location":"en/guide/server-management.html#from-archive","title":"From Archive","text":"<ol> <li>Select \"Import\" from the main menu</li> <li>Choose \"Import archive\"</li> <li>Browse and select a <code>.zip</code> file</li> <li>MSTL extracts to <code>servers/&lt;folder&gt;/</code></li> <li>Scans and detects the core jar (prompts if multiple found)</li> <li>Auto-generates <code>.server.json</code></li> </ol>"},{"location":"en/guide/server-management.html#from-directory","title":"From Directory","text":"<p>Specify an existing server directory. MSTL copies it to <code>servers/</code> and configures it automatically.</p>"},{"location":"en/guide/server-management.html#multiple-servers","title":"Multiple Servers","text":"<p>Each server is an independent child process. You can:</p> <ul> <li>Start one server, return to the menu, and start another</li> <li>Manage plugins, mods, and settings independently</li> <li>Instances are fully isolated</li> </ul>"}]}